import React, { useEffect, useRef, useState } from 'react';
import { GoogleGenAI, LiveServerMessage, Modality, Type, FunctionDeclaration } from "@google/genai";
import { Mic, MicOff, X, Activity, MessageSquare, UserCog, RefreshCw, Users, Volume2 } from 'lucide-react';
import { GameState, Language, LiveVoice, CharacterRegistrationHandler, StatUpdateHandler, XpUpdateHandler, SurvivalUpdateHandler } from '../types';
import { createPcmBlob, decodeAudioData, base64ToUint8Array } from '../utils/audio';
import Sidebar from './Sidebar';

interface LiveSessionProps {
  isOpen: boolean;
  onClose: () => void;
  gameState: GameState;
  language: Language;
  onInventoryUpdate: (items: string[]) => void;
  onQuestUpdate: (quest: string) => void;
  onRegisterCharacter: CharacterRegistrationHandler;
  onStatUpdate: StatUpdateHandler;
  onXpUpdate: XpUpdateHandler;
  onSurvivalUpdate: SurvivalUpdateHandler;
}

const LiveSession: React.FC<LiveSessionProps> = ({ 
  isOpen, 
  onClose, 
  gameState, 
  language,
  onInventoryUpdate,
  onQuestUpdate,
  onRegisterCharacter,
  onStatUpdate,
  onXpUpdate,
  onSurvivalUpdate
}) => {
  const [status, setStatus] = useState<'connecting' | 'connected' | 'error'>('connecting');
  const [isMicOn, setIsMicOn] = useState(true);
  const [selectedVoice, setSelectedVoice] = useState<LiveVoice>('Kore');

  // Refs for audio handling
  const audioContextRef = useRef<AudioContext | null>(null);
  const inputContextRef = useRef<AudioContext | null>(null);
  const processorRef = useRef<ScriptProcessorNode | null>(null);
  const sourceRef = useRef<MediaStreamAudioSourceNode | null>(null);
  const analyserRef = useRef<AnalyserNode | null>(null);
  const outputAnalyserRef = useRef<AnalyserNode | null>(null); // For visualizing AI audio
  const streamRef = useRef<MediaStream | null>(null);
  const nextStartTimeRef = useRef<number>(0);
  const sessionPromiseRef = useRef<Promise<any> | null>(null);
  const activeSessionRef = useRef<any>(null);
  const sourcesRef = useRef<Set<AudioBufferSourceNode>>(new Set());

  // Refs for visualization
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const situationRef = useRef<HTMLDivElement>(null); // Ref for visual indicator on dialog
  const animationFrameRef = useRef<number | null>(null);

  // Refs for cleanup and state access inside closures
  const mountedRef = useRef(true);
  const isMicOnRef = useRef(true);

  // Define tools
  const updateInventoryTool: FunctionDeclaration = {
    name: "update_inventory",
    description: "Update the user's inventory list. Call this IMMEDIATELY whenever the user finds, buys, or loses an item.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        items: {
          type: Type.ARRAY,
          items: { type: Type.STRING },
          description: "The complete new list of inventory items."
        }
      },
      required: ["items"]
    }
  };

  const updateQuestTool: FunctionDeclaration = {
    name: "update_quest",
    description: "Update the current quest. Call this IMMEDIATELY when the objective changes.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        quest: {
          type: Type.STRING,
          description: "The new quest description."
        }
      },
      required: ["quest"]
    }
  };

  const registerCharacterTool: FunctionDeclaration = {
    name: "register_character",
    description: "Register a new character and their specific voice profile when they first speak.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        name: {
          type: Type.STRING,
          description: "Name of the character (e.g., 'Grog', 'Princess Elara')."
        },
        voiceDescription: {
          type: Type.STRING,
          description: "Description of the voice used (e.g., 'Deep and gravelly', 'High-pitched and fast')."
        }
      },
      required: ["name", "voiceDescription"]
    }
  };

  const updateStatsTool: FunctionDeclaration = {
    name: "update_stats",
    description: "Update character stats based on user actions. Use this to simulate character growth or fatigue.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        strength: { type: Type.NUMBER, description: "New Strength value." },
        intelligence: { type: Type.NUMBER, description: "New Intelligence value." },
        stamina: { type: Type.NUMBER, description: "New Stamina value." },
        charisma: { type: Type.NUMBER, description: "New Charisma value." }
      }
    }
  };

  const updateSurvivalTool: FunctionDeclaration = {
    name: "update_survival",
    description: "Update survival stats (Hunger/Thirst). Reduce them over time or increase them when eating/drinking.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        hungerChange: { type: Type.NUMBER, description: "Change in hunger (e.g., -5 for time, +30 for food)." },
        thirstChange: { type: Type.NUMBER, description: "Change in thirst (e.g., -5 for time, +30 for drink)." }
      },
      required: ["hungerChange", "thirstChange"]
    }
  };

  const grantXpTool: FunctionDeclaration = {
    name: "grant_xp",
    description: "Grant XP to the user for actions.",
    parameters: {
      type: Type.OBJECT,
      properties: {
        amount: { type: Type.NUMBER, description: "Amount of XP to grant." },
        levelUp: { type: Type.BOOLEAN, description: "Whether this triggered a level up (calculated by you)." }
      },
      required: ["amount"]
    }
  };

  // Sync ref with state
  useEffect(() => {
    isMicOnRef.current = isMicOn;
  }, [isMicOn]);

  useEffect(() => {
    mountedRef.current = true;
    if (isOpen) {
      startSession();
    }

    return () => {
      mountedRef.current = false;
      stopSession();
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isOpen, selectedVoice]);

  const isIgnorableError = (error: any) => {
    const msg = error instanceof Error ? error.message : String(error);
    const lowerMsg = msg.toLowerCase();
    return (
      lowerMsg.includes("deadline") ||
      lowerMsg.includes("cancelled") ||
      lowerMsg.includes("aborted") ||
      lowerMsg.includes("connection closed")
    );
  };

  const startSession = async () => {
    setStatus('connecting');

    try {
      const apiKey = process.env.API_KEY;
      if (!apiKey) throw new Error("API Key missing");

      const ai = new GoogleGenAI({ apiKey });

      // Audio Contexts
      const AudioContextClass = window.AudioContext || (window as any).webkitAudioContext;
      const inputCtx = new AudioContextClass({ sampleRate: 16000 });
      const outputCtx = new AudioContextClass({ sampleRate: 24000 });

      inputContextRef.current = inputCtx;
      audioContextRef.current = outputCtx;
      nextStartTimeRef.current = 0;

      // Microphone Stream
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      streamRef.current = stream;

      const source = inputCtx.createMediaStreamSource(stream);
      sourceRef.current = source;

      // Input Analyser (Mic)
      const analyser = inputCtx.createAnalyser();
      analyser.fftSize = 256;
      source.connect(analyser);
      analyserRef.current = analyser;

      // Output Analyser (AI)
      const outputAnalyser = outputCtx.createAnalyser();
      outputAnalyser.fftSize = 256;
      outputAnalyser.smoothingTimeConstant = 0.5;
      outputAnalyser.connect(outputCtx.destination); // Chain: Source -> Analyser -> Destination
      outputAnalyserRef.current = outputAnalyser;

      // Start Visualization Loop
      visualize();

      const processor = inputCtx.createScriptProcessor(4096, 1, 1);
      processorRef.current = processor;

      // Build Context
      const historyContext = gameState.history.length > 0 
          ? gameState.history.slice(-4).map(h => `${h.role === 'model' ? 'GM' : 'Player'}: ${h.text}`).join('\n')
          : "Start of adventure.";

      // Inject known voices
      const voiceRegistryText = gameState.characterRegistry && gameState.characterRegistry.length > 0
          ? gameState.characterRegistry.map(c => `- ${c.name}: ${c.voiceDescription}`).join('\n')
          : "None yet.";

      const contextDesc = `
        Current Quest: ${gameState.currentQuest || 'None'}
        Inventory List: [${gameState.inventory.map(i => i.name).join(', ')}]
        Status: Level ${gameState.level}, XP ${gameState.currentXp}/${gameState.nextLevelXp}
        Stats: STR ${gameState.stats.strength}, INT ${gameState.stats.intelligence}, STA ${gameState.stats.stamina}, CHA ${gameState.stats.charisma}
        Survival: Hunger ${gameState.hunger}/100, Thirst ${gameState.thirst}/100

        KNOWN CHARACTER VOICES (USE THESE PERSISTENTLY):
        ${voiceRegistryText}

        Recent Story History:
        ${historyContext}
      `;

      const systemInstructionText = language === Language.German 
        ? `Du bist ein fortschrittlicher KI-Spielleiter und eine Game Engine.

           KRITISCH - SPIELMECHANIK & STATS:
           - Wenn der Spieler kämpft/trainiert -> Rufe 'update_stats' auf (+Stärke).
           - Wenn der Spieler rennt/reist -> Rufe 'update_stats' auf (+Ausdauer).
           - Du bist verantwortlich für das Inventar, Quests und STATS.
           - SURVIVAL: Der Spieler wird hungrig/durstig. Erwähne es narrativ und nutze 'update_survival' um Hunger/Durst zu senken.

           AUDIO & STIMMEN:
           - Generiere Hintergrundgeräusche und Effekte stimmlich (Wind, Kampf, Schritte).
           - Wenn ein NPC spricht, ÄNDERE DEINE STIMME (Tonhöhe, Akzent).

           KONTEXT:
           ${contextDesc}`
        : `You are an advanced AI Game Master and Game Engine for an infinite RPG.

           *** CRITICAL GAMEPLAY MECHANICS ***
           You must act as a Simulation Engine. Every action has a consequence on stats.
           1. IF User FIGHTS, LIFTS, or BREAKS things -> Call 'update_stats' with (current_strength + 1).
           2. IF User RUNS, CLIMBS, or TRAVELS -> Call 'update_stats' with (current_stamina + 1).

           SURVIVAL ENGINE:
           - The user loses hunger/thirst over time. Call 'update_survival' periodically (e.g., -5).
           - If user eats/drinks, call 'update_survival' with positive values (+30).
           - Narrate the physical sensation of hunger/thirst if low.

           STATE SYNC:
           - If the user finds an item -> Call 'update_inventory'.
           - If the user buys/sells -> Call 'update_inventory' AND describe the gold transaction.

           VOICE ACTING & AUDIO:
           - You are a voice actor performing multiple roles.
           - NARRATOR: Use the selected base voice.
           - NPCs: You MUST drastically change your pitch, speed, and tone for characters.
           - SOUNDSCAPES: Layer vocal sound effects (wind, tavern noise, footsteps).

           GAME CONTEXT:
           ${contextDesc}`;

      const sessionPromise = ai.live.connect({
        model: 'gemini-2.5-flash-native-audio-preview-09-2025',
        callbacks: {
          onopen: () => {
             if(mountedRef.current) setStatus('connected');

             processor.onaudioprocess = (e) => {
               // Use Ref here to ensure we get the latest mic state
               if (!isMicOnRef.current || !mountedRef.current || !activeSessionRef.current) return;
               const inputData = e.inputBuffer.getChannelData(0);
               const pcmBlob = createPcmBlob(inputData);

               // Safe send to prevent crash if session just closed
               try {
                 if (activeSessionRef.current) {
                    activeSessionRef.current.sendRealtimeInput({ media: pcmBlob });
                 }
               } catch (err) {
                 // Ignore send errors during teardown
               }
             };

             source.connect(processor);
             processor.connect(inputCtx.destination);
          },
          onmessage: async (msg: LiveServerMessage) => {
            if (!mountedRef.current) return;

            // Handle Tools
            if (msg.toolCall) {
              for (const fc of msg.toolCall.functionCalls) {
                console.log("Tool Call:", fc.name, fc.args);
                let result = { result: "ok" };

                if (fc.name === "update_inventory") {
                  const newItems = (fc.args as any).items;
                  if (Array.isArray(newItems)) {
                    onInventoryUpdate(newItems);
                    result = { result: "Inventory updated" };
                  }
                } else if (fc.name === "update_quest") {
                  const newQuest = (fc.args as any).quest;
                  if (typeof newQuest === 'string') {
                    onQuestUpdate(newQuest);
                    result = { result: "Quest updated" };
                  }
                } else if (fc.name === "register_character") {
                  const name = (fc.args as any).name;
                  const desc = (fc.args as any).voiceDescription;
                  if (name && desc) {
                    onRegisterCharacter(name, desc);
                    result = { result: "Character voice registered" };
                  }
                } else if (fc.name === "update_stats") {
                   const stats = fc.args as any;
                   onStatUpdate(stats); 
                   result = { result: "Stats updated" };
                } else if (fc.name === "update_survival") {
                   const hungerChange = (fc.args as any).hungerChange;
                   const thirstChange = (fc.args as any).thirstChange;
                   if (typeof hungerChange === 'number' && typeof thirstChange === 'number') {
                     onSurvivalUpdate(hungerChange, thirstChange);
                     result = { result: "Survival updated" };
                   }
                } else if (fc.name === "grant_xp") {
                   const amount = (fc.args as any).amount;
                   const levelUp = (fc.args as any).levelUp || false;
                   if (typeof amount === 'number') {
                      onXpUpdate(amount, levelUp);
                      result = { result: "XP granted" };
                   }
                }

                if (activeSessionRef.current) {
                  try {
                    activeSessionRef.current.sendToolResponse({
                      functionResponses: [{
                        id: fc.id,
                        name: fc.name,
                        response: result
                      }]
                    });
                  } catch (e) {
                    console.warn("Failed to send tool response (session likely closed):", e);
                  }
                }
              }
            }

            // Handle Audio Output
            const base64Audio = msg.serverContent?.modelTurn?.parts?.[0]?.inlineData?.data;
            if (base64Audio && audioContextRef.current && outputAnalyserRef.current) {
               const ctx = audioContextRef.current;
               const uint8 = base64ToUint8Array(base64Audio);
               const buffer = await decodeAudioData(uint8, ctx);

               const src = ctx.createBufferSource();
               src.buffer = buffer;

               // Connect to Analyser (which connects to destination)
               src.connect(outputAnalyserRef.current);

               nextStartTimeRef.current = Math.max(nextStartTimeRef.current, ctx.currentTime);
               src.start(nextStartTimeRef.current);
               nextStartTimeRef.current += buffer.duration;

               sourcesRef.current.add(src);
               src.onended = () => sourcesRef.current.delete(src);
            }

            if (msg.serverContent?.interrupted) {
               sourcesRef.current.forEach(s => {
                 try { s.stop(); } catch(e) {}
               });
               sourcesRef.current.clear();
               nextStartTimeRef.current = 0;
            }
          },
          onclose: () => {
            console.log("Live session closed");
          },
          onerror: (err) => {
            if (isIgnorableError(err)) {
              console.warn("Suppressing transient session error:", err);
              return;
            }
            console.error("Live session error", err);
            if(mountedRef.current) setStatus('error');
          }
        },
        config: {
           responseModalities: [Modality.AUDIO],
           speechConfig: {
             voiceConfig: { prebuiltVoiceConfig: { voiceName: selectedVoice } }
           },
           systemInstruction: systemInstructionText,
           tools: [{ functionDeclarations: [updateInventoryTool, updateQuestTool, registerCharacterTool, updateStatsTool, updateSurvivalTool, grantXpTool] }]
        }
      });

      sessionPromiseRef.current = sessionPromise;

      sessionPromise.then(session => {
        if (!mountedRef.current) {
          session.close();
          return;
        }
        activeSessionRef.current = session;
      }).catch(e => {
        if (isIgnorableError(e)) {
           console.warn("Session connection cancelled or timed out (suppressed).");
           return;
        }
        console.error("Failed to establish session:", e);
        if(mountedRef.current) setStatus('error');
      });

    } catch (e) {
      console.error("Failed to start live session", e);
      setStatus('error');
    }
  };

  const visualize = () => {
    if (!canvasRef.current || !analyserRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const analyser = analyserRef.current;
    const outputAnalyser = outputAnalyserRef.current;
    const bufferLength = analyser.frequencyBinCount;
    const inputDataArray = new Uint8Array(bufferLength);
    const outputDataArray = new Uint8Array(bufferLength);

    const draw = () => {
      if (!mountedRef.current) return;

      animationFrameRef.current = requestAnimationFrame(draw);
      analyser.getByteFrequencyData(inputDataArray);

      let outputVol = 0;
      if (outputAnalyser) {
        outputAnalyser.getByteFrequencyData(outputDataArray);
        outputVol = outputDataArray.reduce((a, b) => a + b, 0) / bufferLength;
      }

      // Calculate Input Volume
      const inputVol = inputDataArray.reduce((a, b) => a + b, 0) / bufferLength;

      // Determine who is "dominant" (Who to visualize)
      const isAiSpeaking = outputVol > 5; // Low threshold for AI audio detection
      const dataToDraw = isAiSpeaking ? outputDataArray : inputDataArray;

      // --- VISUAL INDICATOR UPDATE ---
      // Efficiently update DOM without triggering React render loop
      if (situationRef.current) {
        if (isAiSpeaking) {
           situationRef.current.style.borderColor = 'rgba(34, 211, 238, 0.8)'; // Cyan
           situationRef.current.style.boxShadow = '0 0 20px rgba(34, 211, 238, 0.2)';
           situationRef.current.style.backgroundColor = 'rgba(34, 211, 238, 0.05)';
        } else {
           situationRef.current.style.borderColor = 'rgba(51, 65, 85, 0.5)'; // Slate-700/50
           situationRef.current.style.boxShadow = 'none';
           situationRef.current.style.backgroundColor = 'rgba(15, 23, 42, 0.5)';
        }
      }

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const barWidth = (canvas.width / bufferLength) * 2.5;
      let barHeight;
      let x = 0;
      const centerX = canvas.width / 2;

      // Draw Loop
      for(let i = 0; i < bufferLength; i++) {
          barHeight = dataToDraw[i] / 2;

          if (isAiSpeaking) {
            // Cyan/Blue for AI
             const r = barHeight + 50;
             ctx.fillStyle = `rgb(${50}, ${Math.min(255, r + 100)}, ${255})`;
          } else if (isMicOnRef.current) {
            // Amber/Orange for User, only if mic is on (Ref check)
             const r = barHeight + 25 * (i/bufferLength);
             ctx.fillStyle = `rgb(${Math.min(255, r + 100)}, ${150}, ${50})`;
          } else {
             // Muted when mic off and no AI
             ctx.fillStyle = '#334155'; 
             barHeight = 2; 
          }

          ctx.fillRect(centerX + x, canvas.height/2 - barHeight/2, barWidth, barHeight);
          ctx.fillRect(centerX - x - barWidth, canvas.height/2 - barHeight/2, barWidth, barHeight);

          x += barWidth + 1;
          if (x > canvas.width/2) break;
      }

      // Add "Active" indicator text on canvas
      ctx.font = 'bold 12px sans-serif';
      ctx.textAlign = 'right';

      if (isAiSpeaking) {
          ctx.fillStyle = '#22d3ee';
          ctx.fillText(language === Language.German ? "AI SPRICHT" : "AI SPEAKING", canvas.width - 10, 20);
          // Pulsing circle
          ctx.beginPath();
          ctx.arc(canvas.width - 100, 16, 4, 0, 2 * Math.PI);
          ctx.fill();
      } else if (isMicOnRef.current) {
          ctx.fillStyle = '#f59e0b';
          ctx.fillText(language === Language.German ? "Hört zu..." : "Listening...", canvas.width - 10, 20);
      } else {
          ctx.fillStyle = '#64748b';
          ctx.fillText("Muted", canvas.width - 10, 20);
      }
    };

    draw();
  };

  const stopSession = async () => {
    if (animationFrameRef.current) {
      cancelAnimationFrame(animationFrameRef.current);
    }
    if (streamRef.current) {
      streamRef.current.getTracks().forEach(t => t.stop());
      streamRef.current = null;
    }
    if (sourceRef.current) {
      sourceRef.current.disconnect();
      sourceRef.current = null;
    }
    if (processorRef.current) {
      processorRef.current.onaudioprocess = null; // Important: Stop processing immediately
      processorRef.current.disconnect();
      processorRef.current = null;
    }
    if (inputContextRef.current) {
      if (inputContextRef.current.state !== 'closed') {
        inputContextRef.current.close();
      }
      inputContextRef.current = null;
    }
    if (audioContextRef.current) {
      if (audioContextRef.current.state !== 'closed') {
        audioContextRef.current.close();
      }
      audioContextRef.current = null;
    }
    sourcesRef.current.forEach(s => {
      try { s.stop(); } catch(e) {}
    });
    sourcesRef.current.clear();

    if (activeSessionRef.current) {
      const session = activeSessionRef.current;
      activeSessionRef.current = null; // Clear immediately
      try {
        await session.close();
      } catch (e) {
        console.warn("Error closing session:", e);
      }
    }
  };

  const toggleMic = () => {
    setIsMicOn(!isMicOn);
  };

  if (!isOpen) return null;

  const isGerman = language === Language.German;

  const lastBotTurn = [...gameState.history].reverse().find(t => t.role === 'model');
  const suggestions = lastBotTurn?.choices && lastBotTurn.choices.length > 0 
    ? lastBotTurn.choices 
    : isGerman 
      ? ["Schau dich um", "Überprüfe das Inventar", "Wer bist du?", "Gehe nach Norden"]
      : ["Look around", "Check inventory", "Who are you?", "Go North"];

  const lastNarrative = lastBotTurn?.text 
    ? (lastBotTurn.text.length > 150 ? lastBotTurn.text.substring(0, 150) + "..." : lastBotTurn.text)
    : (isGerman ? "Das Abenteuer beginnt..." : "The adventure begins...");

  return (
    <div className="fixed inset-0 bg-slate-950 z-50 flex animate-in fade-in duration-300">

      <div className="hidden lg:block w-72 border-r border-slate-800 bg-slate-900">
         <Sidebar gameState={gameState} language={language} />
      </div>

      <div className="flex-1 flex flex-col relative">

        <div className="absolute top-4 right-4 z-10">
           <button 
             onClick={onClose}
             className="px-4 py-2 rounded-full bg-red-900/30 text-red-400 hover:bg-red-900/50 border border-red-900/50 flex items-center gap-2 transition-colors"
           >
             <X size={18} />
             <span className="text-sm font-medium">{isGerman ? 'Beenden' : 'End Session'}</span>
           </button>
        </div>

        {/* Voice Selector */}
        <div className="absolute top-4 left-4 lg:left-8 z-10">
           <div className="flex items-center gap-2 bg-slate-900/80 backdrop-blur border border-slate-700 rounded-full px-3 py-1.5">
             <UserCog size={16} className="text-amber-500" />
             <select 
               value={selectedVoice}
               onChange={(e) => setSelectedVoice(e.target.value as LiveVoice)}
               className="bg-transparent text-xs sm:text-sm text-slate-300 outline-none cursor-pointer"
             >
               <option value="Kore">Kore (Balanced)</option>
               <option value="Fenrir">Fenrir (Deep)</option>
               <option value="Puck">Puck (Playful)</option>
               <option value="Charon">Charon (Mysterious)</option>
             </select>
           </div>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center p-8 relative">

           <div className="mb-8 text-center space-y-2">
              <h2 className="text-3xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-amber-400 to-amber-600 fantasy-font">
                {isGerman ? 'Live Abenteuer' : 'Live Adventure'}
              </h2>
              <div className="flex items-center justify-center gap-2 text-sm">
                {status === 'connecting' && <span className="text-amber-500 animate-pulse">● Connecting...</span>}
                {status === 'connected' && <span className="text-emerald-500">● Live</span>}
                {status === 'error' && (
                  <button onClick={() => startSession()} className="text-red-500 flex items-center gap-1 hover:underline">
                    <RefreshCw size={12} /> Retry
                  </button>
                )}
              </div>
           </div>

           <div className="w-full max-w-2xl h-48 bg-slate-900/50 rounded-2xl border border-slate-800 flex items-center justify-center overflow-hidden shadow-2xl relative mb-8">
              <canvas 
                ref={canvasRef} 
                width={600} 
                height={200}
                className="w-full h-full absolute inset-0 opacity-80"
              />
              <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                 {status === 'connecting' && <Activity className="text-amber-500 animate-pulse" size={48} />}
                 {status === 'error' && <Activity className="text-red-500" size={48} />}
              </div>
           </div>

           <button 
             onClick={toggleMic}
             disabled={status !== 'connected'}
             className={`p-6 rounded-full transition-all duration-300 transform hover:scale-105 shadow-xl ${
               isMicOn 
                 ? 'bg-amber-600 hover:bg-amber-500 text-white ring-4 ring-amber-500/20' 
                 : 'bg-slate-800 text-slate-500 border border-slate-700 hover:border-slate-500'
             }`}
           >
