      contents: { parts: [{ text: "Fantasy RPG Character Portrait, oil painting style: " + portraitPrompt }] },
      config: {
        imageConfig: {
          aspectRatio: "1:1",
          imageSize: "1K"
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
