import { GoogleGenAI, Type, Modality } from "@google/genai";
import { AIResponse, AppSettings, Language, ImageSize, CharacterStats, InventoryItem, CharacterClass, Blessing, Reputation, Nemesis, SanctuaryState, Enemy, LocationInfo } from "../types";

// Helper to get the AI client. 
const getAIClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    console.warn("API Key not found in process.env");
  }
  return new GoogleGenAI({ apiKey: apiKey });
};

const getSystemInstruction = (
    language: Language, 
    playerClass: CharacterClass, 
    activeBlessings: Blessing[], 
    reputation: Reputation[], 
    activeNemesis: Nemesis | undefined, 
    sanctuary: SanctuaryState | undefined,
    currentAct: number,
    ascensionLevel: number,
    activeEnemy: Enemy | undefined
) => {
  const langName = language === Language.German ? 'German (Deutsch)' : 'English';

  let blessingText = "";
  if (activeBlessings && activeBlessings.length > 0) {
     blessingText = "\nACTIVE BLESSINGS (META-PROGRESSION):\n" + activeBlessings.map(b => `- ${b.name}: ${b.description}`).join('\n') + "\nEnsure these blessings are reflected in the narrative (e.g. extra damage, better prices).";
  }

  let sanctuaryText = "";
  if (sanctuary) {
    sanctuaryText = `\nSANCTUARY (BASE) LEVELS:\n- Library Level: ${sanctuary.libraryLevel} (Unlock lore hints/weaknesses)\n- Armory Level: ${sanctuary.armoryLevel} (Acknowledge superior starting training)\n- Garden Level: ${sanctuary.gardenLevel} (Acknowledge herbal knowledge)\n\nIf Library Level > 0, you MUST occasionally add [HINT] text revealing hidden info about enemies/locations.`;
  }

  let enemyText = "";
  if (activeEnemy) {
     enemyText = `\nCURRENT COMBAT: Player is fighting ${activeEnemy.name} (HP: ${activeEnemy.currentHp}/${activeEnemy.maxHp}).
     - If player attacks, calculate damage and populate 'combat.damageDealtToEnemy'.
     - If enemy reaches 0 HP, populate 'combat.enemyDefeated': true.
     - Narrate the blow-by-blow action.`;
  }

  return `
You are the Game Engine and Dungeon Master of an infinite RPG. 
Your goal is to simulate a realistic, evolving world where ACTIONS have CONSEQUENCES.

PLAYER IDENTITY:
- Class: ${playerClass}
- The player is mortal. Combat is dangerous.

*** GAME ENGINE ALGORITHMS (STRICTLY FOLLOW) ***

1. COMBAT & ENEMIES:
   - **New Encounter**: If a fight starts, populate 'combat.newEnemy' object. Give them HP based on Act number (Act 1: 20-30HP, Act 3: 100HP).
   - **Damage**: Use 'combat.damageDealtToEnemy' to track hits.
   - **Victory**: Use 'combat.enemyDefeated' when HP hits 0.

2. SURVIVAL ALGORITHM (HUNGER & THIRST):
   - **Time Passing**: Every turn, decrease Hunger by 2-5 and Thirst by 3-6.
   - **Strenuous Action**: If running/fighting, decrease Hunger by 10 and Thirst by 15.
   - **Restoration**: If the player eats food -> Increase Hunger by 20-50. If drinks water -> Increase Thirst by 30-60.
   - **Death**: If Hunger <= 0, return 'causeOfDeath': "Starvation". If Thirst <= 0, return 'causeOfDeath': "Dehydration".

3. HEALTH & DAMAGE:
   - **Taking Damage**: If the player is attacked, they MUST lose HP via 'hpChange' (negative).
   - **Healing**: Eating/Potions -> 'hpChange' (positive).
   - **Death**: If HP drops <= 0, return 'causeOfDeath'.

4. LOCATION TRACKING:
   - Always update the 'location' object.
   - 'biome': "Forest", "Desert", "City", "Dungeon", "Tavern", "Mountain".
   - This drives the visuals.

5. STATS:
   - Increment stats based on usage. Fight -> STR+1. Run -> STA+1. Talk -> CHA+1.

CONTEXT:
${blessingText}
${sanctuaryText}
${enemyText}

IMPORTANT: 
- Generate 'narrative' in ${langName}.
- Generate 'visualPrompt' in ENGLISH.

Return strict JSON matching the schema.
`;
};

export const generateStoryTurn = async (
  historyText: string,
  userAction: string,
  currentInventory: InventoryItem[],
  currentQuest: string,
  currentStats: CharacterStats,
  currentLevel: number,
  currentXp: number,
  nextLevelXp: number,
  playerClass: CharacterClass,
  settings: AppSettings,
  activeBlessings: Blessing[],
  currentReputation: Reputation[],
  activeNemesis: Nemesis | undefined,
  sanctuary: SanctuaryState | undefined,
  currentAct: number,
  actProgress: number,
  ascensionLevel: number,
  currentHunger: number,
  currentThirst: number,
  activeEnemy: Enemy | undefined,
  currentLocation: LocationInfo | undefined
): Promise<AIResponse> => {
  const ai = getAIClient();

  const prompt = `
    CURRENT GAME STATE:
    - Player: Level ${currentLevel} ${playerClass}
    - Stats: STR ${currentStats.strength}, INT ${currentStats.intelligence}, STA ${currentStats.stamina}, CHA ${currentStats.charisma}
    - Survival: Hunger ${currentHunger}, Thirst ${currentThirst}
    - Location: ${currentLocation ? `${currentLocation.name} (${currentLocation.biome})` : "Unknown"}
    - Active Enemy: ${activeEnemy ? `${activeEnemy.name} (HP ${activeEnemy.currentHp})` : "None"}

    Previous Story Context:
    ${historyText}

    User Action: ${userAction}

    Generate response in ${settings.language === Language.German ? 'German' : 'English'}.
    If user attacks active enemy, calculate damage (e.g. 5-10 based on STR) and put it in 'combat.damageDealtToEnemy'.
  `;

  const modelName = settings.textModel;
  const systemInstruction = getSystemInstruction(settings.language, playerClass, activeBlessings, currentReputation, activeNemesis, sanctuary, currentAct, ascensionLevel, activeEnemy);

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            narrative: { type: Type.STRING },
            inventory: { 
              type: Type.ARRAY, 
              items: { 
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  rarity: { type: Type.STRING, enum: ["common", "uncommon", "rare", "epic", "legendary"] },
                  type: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["name", "rarity", "type"]
              } 
            },
            combat: {
              type: Type.OBJECT,
              properties: {
                newEnemy: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    description: { type: Type.STRING },
                    maxHp: { type: Type.NUMBER },
                    currentHp: { type: Type.NUMBER },
                    type: { type: Type.STRING }
                  },
                  required: ["name", "maxHp", "type"]
                },
                damageDealtToEnemy: { type: Type.NUMBER },
                enemyDefeated: { type: Type.BOOLEAN }
              }
            },
            location: {
               type: Type.OBJECT,
               properties: {
                  name: { type: Type.STRING },
                  description: { type: Type.STRING },
                  biome: { type: Type.STRING }
               },
               required: ["name", "biome"]
            },
            goldChange: { type: Type.NUMBER },
            currentQuest: { type: Type.STRING },
            visualPrompt: { type: Type.STRING },
            portraitPrompt: { type: Type.STRING },
            choices: { 
              type: Type.ARRAY, 
              items: { type: Type.STRING } 
            },
            stats: {
              type: Type.OBJECT,
              properties: {
                strength: { type: Type.NUMBER },
                intelligence: { type: Type.NUMBER },
                stamina: { type: Type.NUMBER },
                charisma: { type: Type.NUMBER }
              },
              required: ["strength", "intelligence", "stamina", "charisma"]
            },
            hpChange: { type: Type.NUMBER },
            hungerChange: { type: Type.NUMBER },
            thirstChange: { type: Type.NUMBER },
            causeOfDeath: { type: Type.STRING },
            level: { type: Type.NUMBER },
            currentXp: { type: Type.NUMBER },
            nextLevelXp: { type: Type.NUMBER },
            newAbilities: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                  name: { type: Type.STRING },
                  description: { type: Type.STRING }
                },
                required: ["name", "description"]
              }
            },
            skillCheck: {
              type: Type.OBJECT,
              properties: {
                attribute: { type: Type.STRING, enum: ["strength", "intelligence", "stamina", "charisma"] },
                difficultyClass: { type: Type.NUMBER },
                reason: { type: Type.STRING }
              },
              required: ["attribute", "difficultyClass", "reason"]
            },
            reputationChange: {
              type: Type.ARRAY,
              items: {
                 type: Type.OBJECT,
                 properties: {
                    faction: { type: Type.STRING, enum: ["The Solar Vanguard", "The Lunar Syndicate", "The Verdant Circle"] },
                    amount: { type: Type.NUMBER }
                 },
                 required: ["faction", "amount"]
              }
            },
            newCodexEntries: {
              type: Type.ARRAY,
              items: {
                type: Type.OBJECT,
                properties: {
                   id: { type: Type.STRING },
                   name: { type: Type.STRING },
                   category: { type: Type.STRING, enum: ["Bestiary", "Atlas"] },
                   description: { type: Type.STRING },
                   dateUnlocked: { type: Type.NUMBER }
                },
                required: ["id", "name", "category", "description"]
              }
            },
            newCompanion: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                species: { type: Type.STRING },
                personality: { type: Type.STRING }
              },
              required: ["name", "species", "personality"]
            },
            craftingResult: {
              type: Type.OBJECT,
              properties: {
                success: { type: Type.BOOLEAN },
                message: { type: Type.STRING },
                producedItem: {
                  type: Type.OBJECT,
                  properties: {
                    name: { type: Type.STRING },
                    rarity: { type: Type.STRING, enum: ["common", "uncommon", "rare", "epic", "legendary"] },
                    type: { type: Type.STRING },
                    description: { type: Type.STRING }
                  },
                  required: ["name", "rarity", "type"]
                }
              },
              required: ["success", "message"]
            },
            foundShrine: { type: Type.BOOLEAN },
            actProgressChange: { type: Type.NUMBER },
            isBossFight: { type: Type.BOOLEAN },
            isVictory: { type: Type.BOOLEAN }
          },
          required: ["narrative", "inventory", "currentQuest", "visualPrompt", "choices", "stats", "level", "currentXp", "nextLevelXp"]
        }
      }
    });

    const text = response.text;
    if (!text) throw new Error("No text returned from Gemini");

    return JSON.parse(text) as AIResponse;
  } catch (error) {
    console.error("Error generating story:", error);
    // Fallback
    return {
      narrative: settings.language === Language.German 
        ? "Die Verbindung zur Welt schwankt... (API Fehler)"
        : "The connection to the world wavers... (API Error)",
      inventory: currentInventory,
      currentQuest: currentQuest,
      visualPrompt: "A glitch in reality.",
      choices: [settings.language === Language.German ? "Erneut versuchen" : "Try again"],
      stats: currentStats,
      level: currentLevel,
      currentXp: currentXp,
      nextLevelXp: nextLevelXp
    };
  }
};

export const generateSceneImage = async (
  visualPrompt: string, 
  size: ImageSize
): Promise<string | null> => {
  const ai = getAIClient();
  const modelName = 'gemini-3-pro-image-preview';

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts: [{ text: visualPrompt }] },
      config: {
        imageConfig: {
          aspectRatio: "16:9",
          imageSize: size 
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        return `data:${part.inlineData.mimeType};base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    return null;
  }
};

