// --- Audio Generation Utilities ---
const writeString = (view: DataView, offset: number, string: string) => {
  for (let i = 0; i < string.length; i++) {
    view.setUint8(offset + i, string.charCodeAt(i));
  }
};

const pcmToWavBlob = (base64Data: string): Blob => {
  const binaryString = atob(base64Data);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }

  const wavHeader = new ArrayBuffer(44);
  const view = new DataView(wavHeader);
  const numChannels = 1;
  const sampleRate = 24000;
  const bitsPerSample = 16;
  const byteRate = sampleRate * numChannels * (bitsPerSample / 8);
  const blockAlign = numChannels * (bitsPerSample / 8);

  writeString(view, 0, 'RIFF');
  view.setUint32(4, 36 + len, true);
  writeString(view, 8, 'WAVE');
  writeString(view, 12, 'fmt ');
  view.setUint32(16, 16, true);
  view.setUint16(20, 1, true); 
  view.setUint16(22, numChannels, true);
  view.setUint32(24, sampleRate, true);
  view.setUint32(28, byteRate, true);
  view.setUint16(32, blockAlign, true);
  view.setUint16(34, bitsPerSample, true);
  writeString(view, 36, 'data');
  view.setUint32(40, len, true);

  return new Blob([view, bytes], { type: 'audio/wav' });
};

export const generateNarratedAudio = async (text: string, language: Language): Promise<string> => {
  const ai = getAIClient();
  const modelName = 'gemini-2.5-flash-preview-tts';
  const stylePrefix = language === Language.German 
    ? "Erzähle dies mit einer epischen, filmischen Stimme: " 
    : "Narrate this with an epic, cinematic voice: ";
  const prompt = `${stylePrefix}${text}`;

  try {
    const response = await ai.models.generateContent({
      model: modelName,
      contents: { parts: [{ text: prompt }] },
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Fenrir' } } }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData && part.inlineData.data) {
        const blob = pcmToWavBlob(part.inlineData.data);
        return URL.createObjectURL(blob);
      }
    }
    throw new Error("No audio data returned");
  } catch (error) {
    console.error("Error generating audio:", error);
    throw error;
  }
};

export const checkApiKey = async (): Promise<boolean> => {
  if (typeof window.aistudio !== 'undefined' && window.aistudio.hasSelectedApiKey) {
    return await window.aistudio.hasSelectedApiKey();
  }
  return false;
};

export const requestApiKey = async (): Promise<void> => {
  if (typeof window.aistudio !== 'undefined' && window.aistudio.openSelectKey) {
    await window.aistudio.openSelectKey();
  } else {
    alert("AI Studio environment not detected.");
  }
};

import React, { useState, useEffect, useCallback, useRef } from 'react';
import { GameState, GameTurn, AppSettings, TextModel, ImageSize, Language, CharacterStats, InventoryItem, Ability, CharacterClass, CodexEntry, SkillCheck, MetaState, Blessing, PastHero, BLESSINGS, Reputation, FactionName, Achievement, ACHIEVEMENTS_LIST, Nemesis, SanctuaryState, LegacyItem } from './types';
import Sidebar from './components/Sidebar';
import StoryFeed from './components/StoryFeed';
import SettingsModal from './components/SettingsModal';
import LiveSession from './components/LiveSession';
import ClassSelection from './components/ClassSelection';
import DiceRoller from './components/DiceRoller';
import GameOverModal from './components/GameOverModal';
import VictoryModal from './components/VictoryModal';
import Pantheon from './components/Pantheon';
import AchievementToast from './components/AchievementToast';
import { generateStoryTurn, generateSceneImage, checkApiKey, requestApiKey, generateNarratedAudio, generateCharacterImage, generateCompanionImage, generateEnemyImage, generateMapImage } from './services/geminiService';
import { Send, Settings, Menu, AlertTriangle, Mic, MessageSquare, Headphones, Zap, Gift, Trophy, Archive } from 'lucide-react';

const INITIAL_PROMPTS = {
  [Language.English]: "Start the adventure. I have just arrived in the region.",
  [Language.German]: "Beginne das Abenteuer. Ich bin gerade in der Region angekommen.",
};

const STORAGE_KEY = 'infinity_quest_save_v3'; 
const META_STORAGE_KEY = 'infinity_quest_meta_v1';

const DEFAULT_STATS: CharacterStats = {
  strength: 10,
  intelligence: 10,
  stamina: 10,
  charisma: 10
};

const DEFAULT_SANCTUARY: SanctuaryState = {
  libraryLevel: 0,
  armoryLevel: 0,
  gardenLevel: 0,
  treasuryLevel: 0
};

const INITIAL_REPUTATION: Reputation[] = [
  { faction: 'The Solar Vanguard', value: 0, status: 'Neutral' },
  { faction: 'The Lunar Syndicate', value: 0, status: 'Neutral' },
  { faction: 'The Verdant Circle', value: 0, status: 'Neutral' }
];

function App() {
  const [apiKeyReady, setApiKeyReady] = useState<boolean>(false);
  const [loading, setLoading] = useState<boolean>(false);
  const [input, setInput] = useState<string>('');
  const [sidebarOpen, setSidebarOpen] = useState<boolean>(false);
  const [settingsOpen, setSettingsOpen] = useState<boolean>(false);
  const [liveSessionOpen, setLiveSessionOpen] = useState<boolean>(false);
  const [gameStarted, setGameStarted] = useState<boolean>(false);

  // FX States
  const [damageShake, setDamageShake] = useState(false);
  const [healPulse, setHealPulse] = useState(false);

  // Meta State
  const [metaState, setMetaState] = useState<MetaState>({ 
     soulShards: 0, 
     pastHeroes: [], 
     lastOracleClaim: 0, 
     sanctuary: DEFAULT_SANCTUARY,
     legacyItems: [],
     ascensionLevel: 0
  });
  const [showPantheon, setShowPantheon] = useState<boolean>(false);

  // Selection States
  const [showClassSelection, setShowClassSelection] = useState<boolean>(false);
  const [pendingAbilities, setPendingAbilities] = useState<Ability[] | null>(null);

  // Dice Roll State
  const [activeSkillCheck, setActiveSkillCheck] = useState<SkillCheck | null>(null);

  // Achievement State
  const [currentAchievement, setCurrentAchievement] = useState<Achievement | null>(null);

  const [settings, setSettings] = useState<AppSettings>({
    textModel: TextModel.Pro,
    imageSize: ImageSize.Size_1K,
    autoGenerateImages: true,
    language: Language.English,
  });

  const [gameState, setGameState] = useState<GameState>({
    inventory: [],
    gold: 0,
    currentQuest: "",
    history: [],
    characterRegistry: [],
    isGameOver: false,
    isVictory: false,
    level: 1,
    currentXp: 0,
    nextLevelXp: 1000,
    stats: DEFAULT_STATS,
    currentHp: 20,
    maxHp: 20,
    hunger: 100,
    thirst: 100,
    abilities: [],
    playerClass: 'Traveler',
    title: 'Novice',
    codex: [],
    activeBlessings: [],
    reputation: INITIAL_REPUTATION,
    unlockedAchievements: [],
    currentAct: 1,
    actProgress: 0,
    isBossFight: false,
    ascensionLevel: 0,
    activeEnemy: undefined,
    location: undefined,
    maps: {}
  });

  // Track previous HP for damage shake
  const prevHpRef = useRef(gameState.currentHp);

  useEffect(() => {
    const verifyKey = async () => {
      const hasKey = await checkApiKey();
      setApiKeyReady(hasKey);
    };
    verifyKey();
  }, []);

  // Load Meta State
  useEffect(() => {
    const metaSaved = localStorage.getItem(META_STORAGE_KEY);
    if (metaSaved) {
      try {
        const parsed = JSON.parse(metaSaved);
        if (!parsed.sanctuary) parsed.sanctuary = DEFAULT_SANCTUARY;
        if (!parsed.legacyItems) parsed.legacyItems = [];
        if (typeof parsed.ascensionLevel === 'undefined') parsed.ascensionLevel = 0;
        setMetaState(parsed);
      } catch (e) { console.error("Failed to load meta save", e); }
    }
  }, []);

  // Load / Migrate Game Save
  useEffect(() => {
    const saved = localStorage.getItem(STORAGE_KEY);
    const oldSavedV2 = localStorage.getItem('infinity_quest_save_v2');
    const dataToLoad = saved || oldSavedV2;

    if (dataToLoad) {
      try {
        const parsed = JSON.parse(dataToLoad);
        if (parsed.history && parsed.history.length > 0) {
           // Migration Logic
           if (!parsed.codex) parsed.codex = [];
           if (!parsed.playerClass) parsed.playerClass = 'Traveler';
           if (!parsed.title) parsed.title = 'Novice';
           if (!parsed.currentHp) { parsed.currentHp = 20; parsed.maxHp = 20; }
           if (typeof parsed.hunger === 'undefined') parsed.hunger = 100;
           if (typeof parsed.thirst === 'undefined') parsed.thirst = 100;
           if (!parsed.activeBlessings) parsed.activeBlessings = [];
           if (!parsed.reputation) parsed.reputation = INITIAL_REPUTATION;
           if (!parsed.unlockedAchievements) parsed.unlockedAchievements = [];
           if (typeof parsed.gold === 'undefined') parsed.gold = 0;
           if (typeof parsed.currentAct === 'undefined') parsed.currentAct = 1;
           if (typeof parsed.actProgress === 'undefined') parsed.actProgress = 0;
           if (typeof parsed.isBossFight === 'undefined') parsed.isBossFight = false;
           if (typeof parsed.isVictory === 'undefined') parsed.isVictory = false;
           if (typeof parsed.ascensionLevel === 'undefined') parsed.ascensionLevel = 0;
           if (!parsed.maps) parsed.maps = {};

           setGameState(parsed);
           setGameStarted(true);
        }
      } catch (e) {
        console.error("Failed to load save", e);
      }
    }
  }, []);

  // Auto-Save
  useEffect(() => {
    if (gameState.history.length > 0) {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(gameState));
    }
  }, [gameState]);

  // Check Game Over
  useEffect(() => {
     if (gameStarted && !gameState.isGameOver) {
        if (gameState.currentHp <= 0) {
           setGameState(prev => ({ ...prev, isGameOver: true }));
        } else if (gameState.hunger <= 0) {
           setGameState(prev => ({ ...prev, isGameOver: true, gameOverCause: "Starvation" }));
        } else if (gameState.thirst <= 0) {
           setGameState(prev => ({ ...prev, isGameOver: true, gameOverCause: "Dehydration" }));
        }
     }
  }, [gameState.currentHp, gameState.hunger, gameState.thirst, gameStarted, gameState.isGameOver]);

  // --- FX HANDLER (Shake on Damage) ---
  useEffect(() => {
     if (gameState.currentHp < prevHpRef.current) {
        setDamageShake(true);
        setTimeout(() => setDamageShake(false), 500);
     } else if (gameState.currentHp > prevHpRef.current) {
        setHealPulse(true);
        setTimeout(() => setHealPulse(false), 500);
     }
     prevHpRef.current = gameState.currentHp;
  }, [gameState.currentHp]);

  // --- MAP GENERATION TRIGGER ---
  useEffect(() => {
     const loc = gameState.location;
     if (loc && loc.name && !gameState.maps[loc.name]) {
        // Prevent concurrent generation if called multiple times rapidly
        // We use a functional state update to check existence again safely inside promise logic if needed,
        // but here we just trigger.

        generateMapImage(loc.name, loc.biome).then(url => {
           if (url) {
              setGameState(prev => ({
                 ...prev,
                 maps: { ...prev.maps, [loc.name]: url }
              }));
           }
        });
     }
  }, [gameState.location]); // Dependency on location object reference

  // --- ACHIEVEMENT LISTENER ---
  useEffect(() => {
     if (!gameStarted) return;

     const checkAchievements = () => {
        const newUnlocks: string[] = [];

        // Helper to unlock
        const unlock = (id: string) => {
           if (!gameState.unlockedAchievements?.includes(id)) {
              newUnlocks.push(id);
              const ach = ACHIEVEMENTS_LIST.find(a => a.id === id);
              if (ach) {
                 setCurrentAchievement(ach);
                 // Grant bonus Shards
                 setMetaState(prev => {
                   const newState = { ...prev, soulShards: prev.soulShards + 50 };
                   localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newState));
                   return newState;
                 });
              }
           }
        };

        // Logic
        if (gameState.level >= 5) unlock('survivor');
        if (gameState.inventory.length >= 10) unlock('hoarder');
        if (gameState.gold >= 500) unlock('wealthy');
        if (gameState.stats.charisma >= 16) unlock('social_butterfly');
        if (gameState.companion) unlock('beast_master');
        if (gameState.inventory.some(i => i.rarity === 'legendary')) unlock('legendary_find');
        if (gameState.reputation.some(r => r.status === 'Friendly' || r.status === 'Exalted')) unlock('faction_friend');
        if (gameState.isVictory) unlock('ascended');
        if (gameState.history.length > 5) unlock('first_blood'); // Basic logic for surviving combat (length proxy)

        if (newUnlocks.length > 0) {
           setGameState(prev => ({
              ...prev,
              unlockedAchievements: [...(prev.unlockedAchievements || []), ...newUnlocks]
           }));
        }
     };

     checkAchievements();
  }, [gameState.level, gameState.inventory, gameState.stats, gameState.companion, gameState.reputation, gameState.gold, gameState.isVictory, gameState.history]);


  const handleConnect = async () => {
    try {
      await requestApiKey();
      setApiKeyReady(true);
    } catch (e) {
      console.error("Failed to select key", e);
    }
  };

  const updateReputation = (changes: { faction: FactionName; amount: number }[]) => {
      setGameState(prev => {
         const newRep = prev.reputation.map(r => {
            const change = changes.find(c => c.faction === r.faction);
            if (change) {
               const newValue = Math.max(-100, Math.min(100, r.value + change.amount));
               let status: 'Hostile' | 'Neutral' | 'Friendly' | 'Exalted' = 'Neutral';
               if (newValue <= -50) status = 'Hostile';
               else if (newValue >= 50 && newValue < 90) status = 'Friendly';
               else if (newValue >= 90) status = 'Exalted';
               return { ...r, value: newValue, status };
            }
            return r;
         });
         return { ...prev, reputation: newRep };
      });
  };

  const processTurn = useCallback(async (userAction: string, isInitial: boolean = false, systemOverride?: string) => {
    if ((!userAction.trim() && !isInitial) || pendingAbilities || activeSkillCheck || gameState.isGameOver || gameState.isVictory) return;
    setLoading(true);

    let newHistory = [...gameState.history];
    if (!isInitial && !systemOverride) {
      const userTurn: GameTurn = {
        id: Date.now().toString(),
        role: 'user',
        text: userAction,
      };
      newHistory.push(userTurn);
      setGameState(prev => ({ ...prev, history: newHistory }));
      setInput('');
    }

    const contextText = newHistory
      .slice(-10)
      .map(t => `${t.role === 'user' ? 'Player' : 'Game Master'}: ${t.text}`)
      .join('\n');

    const promptAction = systemOverride || userAction;

    try {
      const aiResponse = await generateStoryTurn(
        contextText,
        promptAction,
        gameState.inventory,
        gameState.currentQuest,
        gameState.stats,
        gameState.level,
        gameState.currentXp,
        gameState.nextLevelXp,
        gameState.playerClass,
        settings,
        gameState.activeBlessings,
        gameState.reputation,
        gameState.activeNemesis,
        metaState.sanctuary,
        gameState.currentAct,
        gameState.actProgress,
        gameState.ascensionLevel,
        gameState.hunger,
        gameState.thirst,
        gameState.activeEnemy,
        gameState.location
      );

      // Handle Skill Check Request
      if (aiResponse.skillCheck) {
        setActiveSkillCheck(aiResponse.skillCheck);
        setLoading(false);
        const partialTurn: GameTurn = {
           id: Date.now().toString() + '-check',
           role: 'model',
           text: aiResponse.narrative + "\n\n[DICE ROLL REQUIRED]",
           imageLoading: false
        };
        setGameState(prev => ({ ...prev, history: [...newHistory, partialTurn] }));
        return; 
      }

      const botTurnId = Date.now().toString() + '-bot';
      const botTurn: GameTurn = {
        id: botTurnId,
        role: 'model',
        text: aiResponse.narrative,
        choices: aiResponse.choices,
        imageLoading: settings.autoGenerateImages,
        isBossTurn: aiResponse.isBossFight // Visual flair
      };

      // Update Combat State
      let nextEnemy = gameState.activeEnemy;

      // 1. Check for New Enemy
      if (aiResponse.combat?.newEnemy) {
         nextEnemy = {
           ...aiResponse.combat.newEnemy,
           maxHp: aiResponse.combat.newEnemy.maxHp, // Type check safe
           currentHp: aiResponse.combat.newEnemy.currentHp || aiResponse.combat.newEnemy.maxHp
         };

         // Generate Enemy Image asynchronously
         generateEnemyImage(nextEnemy.description).then(url => {
            if (url) {
               setGameState(curr => {
                  if (curr.activeEnemy && curr.activeEnemy.name === nextEnemy?.name) {
                     return { ...curr, activeEnemy: { ...curr.activeEnemy, imageUrl: url } };
                  }
                  return curr;
               });
            }
         });
      }

      // 2. Apply Damage to Enemy
      if (nextEnemy && aiResponse.combat?.damageDealtToEnemy) {
         nextEnemy = {
            ...nextEnemy,
            currentHp: Math.max(0, nextEnemy.currentHp - aiResponse.combat.damageDealtToEnemy)
         };
      }

      // 3. Check Defeat
      if (aiResponse.combat?.enemyDefeated) {
         nextEnemy = undefined;
      }

      // Process Codex Updates
      let updatedCodex = [...gameState.codex];
      if (aiResponse.newCodexEntries && aiResponse.newCodexEntries.length > 0) {
        aiResponse.newCodexEntries.forEach(newEntry => {
           if (!updatedCodex.some(e => e.id === newEntry.id)) {
              updatedCodex.push({ ...newEntry, dateUnlocked: Date.now() });
           }
        });
      }

      // Update HP, Hunger, Thirst
      let newHp = gameState.currentHp;
      let newHunger = gameState.hunger;
      let newThirst = gameState.thirst;
      let killerName = gameState.gameOverCause;

      if (aiResponse.hpChange) {
         newHp = Math.min(gameState.maxHp, Math.max(0, newHp + aiResponse.hpChange));
      }
      if (aiResponse.hungerChange) {
         newHunger = Math.min(100, Math.max(0, newHunger + aiResponse.hungerChange));
      }
      if (aiResponse.thirstChange) {
         newThirst = Math.min(100, Math.max(0, newThirst + aiResponse.thirstChange));
      }

      if (aiResponse.causeOfDeath) {
         killerName = aiResponse.causeOfDeath;
      }

      // Update Reputation
      if (aiResponse.reputationChange) {
         updateReputation(aiResponse.reputationChange);
      }

      // Update Gold
      let newGold = gameState.gold;
      if (aiResponse.goldChange) {
         newGold = Math.max(0, newGold + aiResponse.goldChange);
      }

      // Update Act Progress
      let newActProgress = gameState.actProgress;
      let newAct = gameState.currentAct;
      if (aiResponse.actProgressChange) {
         newActProgress = Math.min(100, Math.max(0, newActProgress + aiResponse.actProgressChange));
      }

      setGameState(prev => ({
        ...prev,
        inventory: aiResponse.inventory, 
        currentQuest: aiResponse.currentQuest,
        history: [...newHistory, botTurn],
        // Safety: Ensure stats are merged if AI misses some keys, though schema requires all
        stats: {
           strength: aiResponse.stats.strength ?? prev.stats.strength,
           intelligence: aiResponse.stats.intelligence ?? prev.stats.intelligence,
           stamina: aiResponse.stats.stamina ?? prev.stats.stamina,
           charisma: aiResponse.stats.charisma ?? prev.stats.charisma,
        },
        level: aiResponse.level,
        currentXp: aiResponse.currentXp,
        nextLevelXp: aiResponse.nextLevelXp,
        codex: updatedCodex,
        currentHp: newHp,
        hunger: newHunger,
        thirst: newThirst,
        gameOverCause: killerName,
        gold: newGold,
        foundShrine: aiResponse.foundShrine,
        currentAct: newAct,
        actProgress: newActProgress,
        isBossFight: aiResponse.isBossFight || false,
        isVictory: aiResponse.isVictory || false,
        activeEnemy: nextEnemy,
        location: aiResponse.location || prev.location
      }));

      // Check for Level Up Abilities
      if (aiResponse.newAbilities && aiResponse.newAbilities.length > 0) {
        setPendingAbilities(aiResponse.newAbilities);
      }

      // Generate Portrait
      if (aiResponse.portraitPrompt) {
         generateCharacterImage(aiResponse.portraitPrompt).then(url => {
            if (url) setGameState(prev => ({ ...prev, portraitUrl: url }));
         });
      }

      // Check for New Companion
      if (aiResponse.newCompanion) {
         const companion = aiResponse.newCompanion;
         setGameState(prev => ({ ...prev, companion: companion }));
         generateCompanionImage(`${companion.species}, ${companion.personality}`).then(url => {
            if (url) {
               setGameState(prev => prev.companion ? ({ ...prev, companion: { ...prev.companion, portraitUrl: url } }) : prev);
            }
         });
      }

      // Generate Image
      if (settings.autoGenerateImages && aiResponse.visualPrompt) {
        generateSceneImage(aiResponse.visualPrompt, settings.imageSize).then(imageUrl => {
           setGameState(current => {
             const updatedHistory = current.history.map(turn => 
               turn.id === botTurnId ? { ...turn, imageUrl, imageLoading: false } : turn
             );
             return { ...current, history: updatedHistory };
           });
        });
      } else {
        setGameState(current => {
           const updatedHistory = current.history.map(turn => 
             turn.id === botTurnId ? { ...turn, imageLoading: false } : turn
           );
           return { ...current, history: updatedHistory };
         });
      }

    } catch (error) {
      console.error("Turn processing failed", error);
    } finally {
      setLoading(false);
    }
  }, [gameState, settings, pendingAbilities, activeSkillCheck, metaState.sanctuary]);

  const handleSelectAbility = (ability: Ability) => {
    setGameState(prev => ({
      ...prev,
      abilities: [...prev.abilities, ability]
    }));
    setPendingAbilities(null);
  };

  const handleRollComplete = (roll: number) => {
     if (!activeSkillCheck) return;
     const attr = activeSkillCheck.attribute;
     const modifier = Math.floor((gameState.stats[attr] - 10) / 2);
     const total = roll + modifier;
     const isSuccess = total >= activeSkillCheck.difficultyClass;

     const systemMsg = `[SYSTEM: User rolled a ${roll} + ${modifier} (Total: ${total}) for ${activeSkillCheck.attribute}. DC was ${activeSkillCheck.difficultyClass}. Result: ${isSuccess ? 'SUCCESS' : 'FAILURE'}. Narrate the outcome.]`;
     setActiveSkillCheck(null);
     processTurn("", false, systemMsg);
  };

  const handleCraft = (item1: InventoryItem, item2: InventoryItem) => {
     const systemMsg = `[SYSTEM: Player attempts to combine '${item1.name}' and '${item2.name}'. Determine the crafting result.]`;
     processTurn("", false, systemMsg);
  };

  const handleBuryItem = (item: InventoryItem) => {
     // Remove from inventory
     const newInventory = gameState.inventory.filter(i => i !== item);

     // Create Legacy Item
     const legacyItem: LegacyItem = {
        ...item,
        buriedBy: gameState.title + " " + gameState.playerClass,
        buriedAt: Date.now(),
        note: `Buried by Level ${gameState.level} ${gameState.playerClass}`
     };

     setGameState(prev => ({ ...prev, inventory: newInventory, foundShrine: false }));

     setMetaState(prev => {
        const newState = { ...prev, legacyItems: [...prev.legacyItems, legacyItem] };
        localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newState));
        return newState;
     });

     processTurn("", false, `[SYSTEM: Player buried '${item.name}' at the Shrine of Eternity. Narrate a solemn moment.]`);
  };

  const handleGenerateAudio = async (turnId: string, text: string) => {
    setGameState(prev => ({
      ...prev,
      history: prev.history.map(turn => 
        turn.id === turnId ? { ...turn, audioLoading: true, audioError: undefined } : turn
      )
    }));

    try {
      const audioUrl = await generateNarratedAudio(text, settings.language);
      setGameState(prev => ({
        ...prev,
        history: prev.history.map(turn => 
          turn.id === turnId ? { ...turn, audioLoading: false, audioUrl: audioUrl } : turn
        )
      }));
    } catch (e) {
      setGameState(prev => ({
        ...prev,
        history: prev.history.map(turn => 
          turn.id === turnId ? { ...turn, audioLoading: false, audioError: 'Audio generation failed' } : turn
        )
      }));
    }
  };

  // --- META PROGRESSION HANDLERS ---

  const handleOracleClaim = () => {
    setMetaState(prev => {
       const newState = {
          ...prev,
          lastOracleClaim: Date.now(),
          soulShards: prev.soulShards + 100
       };
       localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newState));
       return newState;
    });
  };

  const handleSanctuaryUpgrade = (building: 'library' | 'armory' | 'garden' | 'treasury') => {
     const level = metaState.sanctuary[`${building}Level`];
     const cost = (level + 1) * 200;

     if (metaState.soulShards >= cost) {
        setMetaState(prev => {
           const newState = {
              ...prev,
              soulShards: prev.soulShards - cost,
              sanctuary: {
                 ...prev.sanctuary,
                 [`${building}Level`]: level + 1
              }
           };
           localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newState));
           return newState;
        });
     }
  };

  const handleGameOverContinue = (shardsEarned: number) => {
     // Save Hero to History
     const fallenHero: PastHero = {
        id: Date.now().toString(),
        name: gameState.title + " " + gameState.playerClass,
        class: gameState.playerClass,
        level: gameState.level,
        date: Date.now(),
        score: shardsEarned,
        causeOfDeath: gameState.gameOverCause || "Perished in the void",
        portraitUrl: gameState.portraitUrl,
        ascensionLevel: gameState.ascensionLevel
     };

     // Handle Nemesis Creation
     let newNemesis = metaState.activeNemesis;
     if (gameState.gameOverCause) {
        newNemesis = {
           name: gameState.gameOverCause,
           origin: `Killer of ${fallenHero.name}`,
           defeatedAt: 0
        };
     }

     const newMetaState = {
        ...metaState,
        soulShards: metaState.soulShards + shardsEarned,
        pastHeroes: [...metaState.pastHeroes, fallenHero],
        activeNemesis: newNemesis
     };

     setMetaState(newMetaState);
     localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newMetaState));

     // Wipe Save
     localStorage.removeItem(STORAGE_KEY);
     setGameState(prev => ({ ...prev, isGameOver: false })); // Hides modal
     setGameStarted(false);
     setShowPantheon(true); // Go to shop
  };

  const handleAscension = (shardsEarned: number) => {
     // Save Hero as Winner
     const hero: PastHero = {
        id: Date.now().toString(),
        name: gameState.title + " " + gameState.playerClass,
        class: gameState.playerClass,
        level: gameState.level,
        date: Date.now(),
        score: shardsEarned,
        causeOfDeath: "ASCENDED",
        portraitUrl: gameState.portraitUrl,
        ascensionLevel: gameState.ascensionLevel
     };

     const newMetaState = {
        ...metaState,
        soulShards: metaState.soulShards + shardsEarned,
        pastHeroes: [...metaState.pastHeroes, hero],
        ascensionLevel: metaState.ascensionLevel + 1 // Increase Difficulty
     };

     setMetaState(newMetaState);
     localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newMetaState));

     // Wipe Save
     localStorage.removeItem(STORAGE_KEY);
     setGameState(prev => ({ ...prev, isVictory: false })); // Hides modal
     setGameStarted(false);
     setShowPantheon(true); // Go to shop
  };

  const handleStartRunFromPantheon = (selectedBlessings: Blessing[], legacyItem?: LegacyItem) => {
    // Determine Nemesis to Inject
    const activeNemesis = metaState.activeNemesis;

    // Filter out withdrawn legacy item
    let newLegacyItems = metaState.legacyItems;
    let startingInventory: InventoryItem[] = [];

    if (legacyItem) {
       newLegacyItems = metaState.legacyItems.filter(i => i !== legacyItem);
       startingInventory.push({ 
          name: legacyItem.name, 
          rarity: legacyItem.rarity, 
          type: legacyItem.type, 
          description: legacyItem.description 
       });

       // Update Meta to remove withdrawn item
       const newMetaState = { ...metaState, legacyItems: newLegacyItems };
       setMetaState(newMetaState);
       localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newMetaState));
    }

    setGameState({
      inventory: startingInventory,
      gold: 0,
      currentQuest: "",
      history: [],
      characterRegistry: [],
      isGameOver: false,
      isVictory: false,
      level: 1,
      currentXp: 0,
      nextLevelXp: 1000,
      stats: DEFAULT_STATS,
      currentHp: 20,
      maxHp: 20,
      hunger: 100,
      thirst: 100,
      abilities: [],
      playerClass: 'Traveler',
      title: 'Novice',
      codex: [],
      activeBlessings: selectedBlessings,
      reputation: INITIAL_REPUTATION,
      unlockedAchievements: [],
      activeNemesis: activeNemesis, // Inject Nemesis
      currentAct: 1,
      actProgress: 0,
      isBossFight: false,
      ascensionLevel: metaState.ascensionLevel,
      maps: {}
    });

    // Deduct Shards
    const cost = selectedBlessings.reduce((acc, b) => acc + b.cost, 0);
    const newMetaState = { ...metaState, soulShards: metaState.soulShards - cost };
    setMetaState(newMetaState);
    localStorage.setItem(META_STORAGE_KEY, JSON.stringify(newMetaState));

    setShowPantheon(false);
    setShowClassSelection(true);
  };

  const handleNewGame = () => {
    localStorage.removeItem(STORAGE_KEY);
    // Determine if we should show Pantheon (if they have shards)
    if (metaState.soulShards > 0 || metaState.pastHeroes.length > 0) {
       setShowPantheon(true);
    } else {
       setShowClassSelection(true);
    }
    setGameStarted(false);
    setGameState(prev => ({ ...prev, isGameOver: false, isVictory: false }));
  };

  const handleClassSelection = (cls: CharacterClass, baseStats: CharacterStats, baseItems: InventoryItem[]) => {
     // Apply Blessings & Sanctuary Bonuses
     let finalStats = { ...baseStats };
     let finalItems = [...gameState.inventory, ...baseItems]; // Preserve Legacy Item if exists
     let finalMaxHp = 20;
     let finalGold = 0;

     // Sanctuary Bonuses
     if (metaState.sanctuary.armoryLevel > 0) {
        finalStats.strength += metaState.sanctuary.armoryLevel;
        finalStats.stamina += metaState.sanctuary.armoryLevel;
     }
     if (metaState.sanctuary.treasuryLevel > 0) {
        finalGold += metaState.sanctuary.treasuryLevel * 50;
     }
     if (metaState.sanctuary.gardenLevel > 0) {
        finalItems.push({ name: "Healing Potion", rarity: "common", type: "Consumable", description: "Restores HP." });
        if (metaState.sanctuary.gardenLevel > 1) {
           finalItems.push({ name: "Mana Herb", rarity: "uncommon", type: "Consumable" });
        }
     }

     gameState.activeBlessings.forEach(blessing => {
        if (blessing.id === 'titan_blood') finalMaxHp += 10;
        if (blessing.id === 'scholar_mind') finalStats.intelligence += 2;
        if (blessing.id === 'warrior_spirit') finalStats.strength += 2;
        if (blessing.id === 'merchant_favor') {
           finalItems.push({ name: "Mysterious Artifact", rarity: "rare", type: "Misc", description: "A gift from the gods." });
           finalGold += 50;
        }
     });

     setGameState(prev => ({
       ...prev,
       playerClass: cls,
       stats: finalStats,
       inventory: finalItems,
       gold: finalGold,
       title: 'Novice',
       maxHp: finalMaxHp,
       currentHp: finalMaxHp,
       hunger: 100,
       thirst: 100,
       ascensionLevel: metaState.ascensionLevel,
       maps: {}
     }));
     setShowClassSelection(false);
     setGameStarted(true);
     setTimeout(() => processTurn(INITIAL_PROMPTS[settings.language], true), 100);
  };

  const startTextAdventure = () => {
    // Check Meta for Pantheon
    if (metaState.soulShards > 0 || metaState.pastHeroes.length > 0) {
       setShowPantheon(true);
    } else {
       setShowClassSelection(true);
    }
  };

  const startVoiceAdventure = () => {
    setGameStarted(true);
    setLiveSessionOpen(true);
  };

  // Live Mode Callbacks
  const handleInventoryUpdate = (items: any[]) => {
    const formattedItems: InventoryItem[] = items.map(item => {
      if (typeof item === 'string') return { name: item, rarity: 'common', type: 'Unknown' };
      return item;
    });
    setGameState(prev => ({ ...prev, inventory: formattedItems }));
  };

  const handleQuestUpdate = (quest: string) => {
    setGameState(prev => ({ ...prev, currentQuest: quest }));
  };
  const handleRegisterCharacter = (name: string, desc: string) => {
    setGameState(prev => {
      if (prev.characterRegistry.some(c => c.name === name)) return prev;
      return { ...prev, characterRegistry: [...prev.characterRegistry, { name, voiceDescription: desc }] };
    });
  };
  const handleStatUpdate = (newStats: Partial<CharacterStats>) => {
    setGameState(prev => ({ 
      ...prev, 
      stats: {
         strength: newStats.strength ?? prev.stats.strength,
         intelligence: newStats.intelligence ?? prev.stats.intelligence,
         stamina: newStats.stamina ?? prev.stats.stamina,
         charisma: newStats.charisma ?? prev.stats.charisma,
      }
    }));
  };
  const handleSurvivalUpdate = (hungerChange: number, thirstChange: number) => {
     setGameState(prev => ({
        ...prev,
        hunger: Math.max(0, Math.min(100, prev.hunger + hungerChange)),
        thirst: Math.max(0, Math.min(100, prev.thirst + thirstChange))
     }));
  };
  const handleXpUpdate = (xpAdded: number, levelUp: boolean) => {
    setGameState(prev => {
      let newXp = prev.currentXp + xpAdded;
      let newLevel = prev.level;
      let newNextLevelXp = prev.nextLevelXp;
      if (levelUp || newXp >= newNextLevelXp) {
        newLevel += 1;
        newXp = newXp - newNextLevelXp;
        newNextLevelXp = Math.floor(newNextLevelXp * 1.5);
      }
      return { ...prev, currentXp: newXp, level: newLevel, nextLevelXp: newNextLevelXp };
    });
  };

  if (!apiKeyReady) {
    return (
      <div className="min-h-screen bg-slate-900 flex items-center justify-center p-4">
        <div className="max-w-md w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-slate-700 text-center">
          <AlertTriangle className="text-amber-500 w-16 h-16 mx-auto mb-6" />
          <h1 className="text-2xl font-bold text-white mb-2 fantasy-font">Access Required</h1>
          <p className="text-slate-400 mb-8">Connect your Google Cloud API key to start.</p>
          <button onClick={handleConnect} className="w-full py-3 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded-lg transition-all">Connect API Key</button>
        </div>
      </div>
    );
  }

  // META SCREENS
  if (showPantheon) {
     return <Pantheon metaState={metaState} onStartRun={handleStartRunFromPantheon} onOracleClaim={handleOracleClaim} onSanctuaryUpgrade={handleSanctuaryUpgrade} />;
  }

  if (showClassSelection) {
    return <ClassSelection onSelect={handleClassSelection} language={settings.language} />;
  }

  if (!gameStarted) {
    return (
      <div className="min-h-screen bg-slate-950 flex items-center justify-center p-4 relative overflow-hidden">
        <div className="absolute inset-0 bg-[url('https://images.unsplash.com/photo-1519074069444-1ba4fff66d16?q=80&w=2544')] bg-cover bg-center opacity-20" />
        <div className="relative z-10 max-w-2xl w-full text-center space-y-12">
          <h1 className="text-6xl font-bold text-transparent bg-clip-text bg-gradient-to-r from-amber-400 to-amber-600 fantasy-font">INFINITY QUEST</h1>
          <div className="grid md:grid-cols-2 gap-6">
            <button onClick={startTextAdventure} className="p-8 bg-slate-900/50 hover:bg-slate-800 border border-slate-700 hover:border-amber-500 rounded-2xl flex flex-col items-center gap-4 transition-all">
              <MessageSquare size={32} className="text-indigo-400" />
              <h3 className="text-2xl font-bold text-white">Text Adventure</h3>
              <p className="text-slate-400 text-sm">Classic RPG with loot & leveling.</p>
            </button>
            <button onClick={startVoiceAdventure} className="p-8 bg-slate-900/50 hover:bg-slate-800 border border-slate-700 hover:border-amber-500 rounded-2xl flex flex-col items-center gap-4 transition-all">
              <Headphones size={32} className="text-amber-400" />
              <h3 className="text-2xl font-bold text-white">Voice Adventure</h3>
              <p className="text-slate-400 text-sm">Immersive audio drama mode.</p>
            </button>
          </div>
          <button onClick={() => setSettingsOpen(true)} className="flex items-center gap-2 text-slate-500 mx-auto hover:text-slate-300"><Settings size={16} /> Settings</button>
        </div>
        <SettingsModal isOpen={settingsOpen} onClose={() => setSettingsOpen(false)} settings={settings} onSettingsChange={setSettings} onNewGame={handleNewGame} />
      </div>
    );
  }

  return (
    <div className={`flex h-screen bg-slate-950 text-slate-200 overflow-hidden font-sans transition-all duration-300 ${damageShake ? 'animate-[shake_0.5s_ease-in-out] bg-red-950/20' : ''} ${healPulse ? 'bg-emerald-950/20 transition-colors duration-1000' : ''}`}>
      <style>{`
        @keyframes shake {
          0%, 100% { transform: translateX(0); }
          10%, 30%, 50%, 70%, 90% { transform: translateX(-5px); }
          20%, 40%, 60%, 80% { transform: translateX(5px); }
        }
      `}</style>

      {sidebarOpen && <div className="fixed inset-0 bg-black/80 z-40 lg:hidden" onClick={() => setSidebarOpen(false)} />}
      <div className={`fixed inset-y-0 left-0 z-50 w-80 transform transition-transform duration-300 ease-in-out lg:relative lg:translate-x-0 ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <Sidebar gameState={gameState} className="h-full w-full shadow-2xl lg:shadow-none" language={settings.language} onCraft={handleCraft} />
      </div>

      <div className="flex-1 flex flex-col min-w-0 relative">
        <header className="h-16 border-b border-slate-800 bg-slate-900/50 backdrop-blur flex items-center justify-between px-4">
          <div className="flex items-center gap-4">
            <button onClick={() => setSidebarOpen(true)} className="lg:hidden p-2 text-slate-400"><Menu /></button>
            <span className="lg:hidden font-bold text-amber-500 fantasy-font">INFINITY QUEST</span>
          </div>
          <div className="flex items-center gap-3">
            <button onClick={() => setLiveSessionOpen(true)} className="flex items-center gap-2 px-3 py-1.5 bg-indigo-600/20 text-indigo-300 border border-indigo-500/30 rounded-full text-sm font-medium"><Mic size={16} /> Voice Mode</button>
            <button onClick={() => setSettingsOpen(true)} className="p-2 text-slate-400 hover:text-white"><Settings size={20} /></button>
          </div>
        </header>

        <StoryFeed history={gameState.history} isThinking={loading} language={settings.language} onGenerateAudio={handleGenerateAudio} />

        {/* Shrine / Bury Item Overlay */}
        {gameState.foundShrine && !gameState.isGameOver && !gameState.isVictory && gameState.inventory.length > 0 && (
          <div className="absolute bottom-24 left-1/2 -translate-x-1/2 z-20 animate-in slide-in-from-bottom-4">
             <div className="bg-emerald-900/90 backdrop-blur border border-emerald-500/50 p-4 rounded-xl shadow-2xl text-center max-w-sm">
                <div className="flex items-center justify-center gap-2 text-emerald-300 font-bold mb-2">
                   <Archive size={18} /> Shrine of Eternity
                </div>
                <p className="text-xs text-emerald-100 mb-3">You found a shrine. You may bury one item here for a future hero to find.</p>
                <div className="flex gap-2 overflow-x-auto p-1 custom-scrollbar">
                   {gameState.inventory.map((item, idx) => (
                      <button 
                        key={idx}
                        onClick={() => handleBuryItem(item)}
                        className="flex-shrink-0 px-3 py-1 bg-emerald-800/50 hover:bg-emerald-700 border border-emerald-600/50 rounded text-xs text-white"
                      >
                         Bury {item.name}
                      </button>
                   ))}
                   <button onClick={() => setGameState(prev => ({...prev, foundShrine: false}))} className="px-3 py-1 bg-slate-800 rounded text-xs text-slate-400">Ignore</button>
                </div>
             </div>
          </div>
        )}

        <div className="bg-slate-900 border-t border-slate-800 p-4 z-10">
          <div className="max-w-3xl mx-auto">
            {!loading && gameState.history.length > 0 && (
              <div className="flex flex-wrap gap-2 mb-4">
                {gameState.history[gameState.history.length - 1].choices?.map((choice, idx) => (
                  <button key={idx} onClick={() => processTurn(choice)} className="px-4 py-2 bg-slate-800 hover:bg-slate-700 border border-slate-700 text-slate-300 text-sm rounded-full transition-all">{choice}</button>
                ))}
              </div>
            )}
            <div className="relative flex items-center gap-2">
              <input type="text" value={input} onChange={(e) => setInput(e.target.value)} onKeyDown={(e) => e.key === 'Enter' && processTurn(input)} placeholder="What do you want to do?" disabled={loading || !!pendingAbilities || !!activeSkillCheck || gameState.isGameOver || gameState.isVictory} className="flex-1 bg-slate-950 border border-slate-700 text-white rounded-xl py-4 px-5 focus:outline-none focus:border-amber-500" />
              <button onClick={() => processTurn(input)} disabled={loading || !input.trim() || !!pendingAbilities || !!activeSkillCheck || gameState.isGameOver || gameState.isVictory} className="absolute right-2 p-2 bg-amber-600 hover:bg-amber-500 text-white rounded-lg disabled:opacity-50"><Send size={20} /></button>
            </div>
          </div>
        </div>

        <LiveSession 
           isOpen={liveSessionOpen} 
           onClose={() => setLiveSessionOpen(false)} 
           gameState={gameState} 
           language={settings.language} 
           onInventoryUpdate={handleInventoryUpdate} 
           onQuestUpdate={handleQuestUpdate} 
           onRegisterCharacter={handleRegisterCharacter} 
           onStatUpdate={handleStatUpdate} 
           onXpUpdate={handleXpUpdate} 
           onSurvivalUpdate={handleSurvivalUpdate} 
        />
      </div>

      {/* OVERLAYS */}

      {/* Game Over Screen */}
      <GameOverModal isOpen={gameState.isGameOver} gameState={gameState} onContinue={handleGameOverContinue} />

      {/* Victory Screen */}
      <VictoryModal isOpen={gameState.isVictory} gameState={gameState} onAscend={handleAscension} />

      {/* Achievement Toast */}
      <AchievementToast achievement={currentAchievement} onClose={() => setCurrentAchievement(null)} />

      {/* Dice Roller Overlay */}
      {activeSkillCheck && (
        <DiceRoller 
          check={activeSkillCheck} 
          onRollComplete={handleRollComplete} 
          modifier={Math.floor((gameState.stats[activeSkillCheck.attribute] - 10) / 2)} 
        />
      )}

      {/* Level Up Modal */}
      {pendingAbilities && (
        <div className="fixed inset-0 bg-black/90 z-[60] flex items-center justify-center p-4 animate-in fade-in">
           <div className="max-w-2xl w-full bg-slate-900 border border-amber-500/50 rounded-2xl p-8 relative overflow-hidden shadow-2xl">
              <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-amber-500 via-yellow-400 to-amber-500 animate-pulse" />
              <div className="text-center mb-8">
                 <div className="inline-block p-4 bg-amber-500/10 rounded-full mb-4 border border-amber-500/50">
                   <Trophy size={48} className="text-amber-500" />
                 </div>
                 <h2 className="text-4xl font-bold text-white fantasy-font mb-2">Level Up!</h2>
                 <p className="text-slate-400">Choose a new ability to master.</p>
              </div>
              <div className="grid gap-4 md:grid-cols-3">
                 {pendingAbilities.map((ability, idx) => (
                    <button key={idx} onClick={() => handleSelectAbility(ability)} className="group relative p-6 bg-slate-800 border border-slate-700 hover:border-amber-500 rounded-xl text-left transition-all hover:-translate-y-1 hover:shadow-xl">
                       <div className="absolute top-4 right-4 text-slate-600 group-hover:text-amber-500 transition-colors"><Zap size={20} /></div>
                       <h3 className="font-bold text-lg text-slate-200 group-hover:text-amber-400 mb-2">{ability.name}</h3>
                       <p className="text-sm text-slate-500 group-hover:text-slate-300 leading-relaxed">{ability.description}</p>
                    </button>
                 ))}
              </div>
           </div>
        </div>
      )}

      <SettingsModal isOpen={settingsOpen} onClose={() => setSettingsOpen(false)} settings={settings} onSettingsChange={setSettings} onNewGame={handleNewGame} />
    </div>
  );
}

export default App;

import React, { useState } from 'react';
import { GameState, Language, ItemRarity, CodexCategory, InventoryItem, FactionName, ACHIEVEMENTS_LIST } from '../types';
import { Scroll, Backpack, ShieldAlert, BicepsFlexed, Brain, Activity, MessageCircle, Trophy, Zap, Sword, Book, Map, Skull, Heart, Hammer, Sparkles, X, Cat, Flag, Medal, Coins, ArrowRight, Utensils, Droplets, MapPin, Loader } from 'lucide-react';

interface SidebarProps {
  gameState: GameState;
  className?: string;
  language: Language;
  onCraft?: (item1: InventoryItem, item2: InventoryItem) => void;
}

const Sidebar: React.FC<SidebarProps> = ({ gameState, className = '', language, onCraft }) => {
  const [activeTab, setActiveTab] = useState<'status' | 'inventory' | 'abilities' | 'codex' | 'social'>('status');
  const [codexFilter, setCodexFilter] = useState<CodexCategory>('Bestiary');

  // Crafting State
  const [isCraftingMode, setIsCraftingMode] = useState(false);
  const [selectedCraftItems, setSelectedCraftItems] = useState<InventoryItem[]>([]);

  const isGerman = language === Language.German;

  // Calculate XP Percentage
  const xpPercentage = Math.min(100, Math.max(0, (gameState.currentXp / gameState.nextLevelXp) * 100));

  // Calculate HP Percentage
  const hpPercentage = Math.min(100, Math.max(0, (gameState.currentHp / gameState.maxHp) * 100));

  const getRarityClass = (rarity: ItemRarity) => {
    switch (rarity) {
      case 'uncommon': return 'rarity-uncommon bg-emerald-900/10';
      case 'rare': return 'rarity-rare bg-blue-900/10';
      case 'epic': return 'rarity-epic bg-purple-900/10';
      case 'legendary': return 'rarity-legendary bg-amber-900/10';
      default: return 'rarity-common bg-slate-800/50';
    }
  };

  const getClassIcon = () => {
    switch(gameState.playerClass) {
      case 'Warrior': return <Sword size={16} className="text-red-400"/>;
      case 'Mage': return <Zap size={16} className="text-blue-400"/>;
      case 'Rogue': return <Activity size={16} className="text-green-400"/>;
      case 'Cleric': return <ShieldAlert size={16} className="text-amber-400"/>;
      default: return <Backpack size={16} />;
    }
  };

  const toggleCraftItem = (item: InventoryItem) => {
    if (!isCraftingMode) return;

    if (selectedCraftItems.includes(item)) {
      setSelectedCraftItems(prev => prev.filter(i => i !== item));
    } else {
      if (selectedCraftItems.length < 2) {
        setSelectedCraftItems(prev => [...prev, item]);
      }
    }
  };

  const handleFuse = () => {
    if (selectedCraftItems.length === 2 && onCraft) {
      onCraft(selectedCraftItems[0], selectedCraftItems[1]);
      setIsCraftingMode(false);
      setSelectedCraftItems([]);
    }
  };

  const getReputationColor = (status: string) => {
     switch(status) {
        case 'Hostile': return 'bg-red-500';
        case 'Neutral': return 'bg-slate-500';
        case 'Friendly': return 'bg-emerald-500';
        case 'Exalted': return 'bg-amber-500';
        default: return 'bg-slate-500';
     }
  };

  const getActName = (act: number) => {
     switch(act) {
        case 1: return isGerman ? "Akt I: Das Erwachen" : "Act I: The Awakening";
        case 2: return isGerman ? "Akt II: Der Konflikt" : "Act II: The Conflict";
        case 3: return isGerman ? "Akt III: Der Abgrund" : "Act III: The Abyss";
        default: return "Epilogue";
     }
  };

  return (
    <div className={`bg-slate-900 border-r border-slate-800 flex flex-col h-full overflow-hidden ${className}`}>

      {/* LOCATION HEADER */}
      {gameState.location && (
         <div className="bg-slate-950/80 border-b border-slate-800 px-4 py-2 flex items-center gap-3">
             <div className="w-8 h-8 rounded-full bg-slate-900 flex items-center justify-center border border-slate-700">
                <MapPin size={16} className="text-slate-400" />
             </div>
             <div className="flex-1 min-w-0">
                <div className="text-xs text-slate-500 font-bold uppercase tracking-wider truncate">{gameState.location.biome}</div>
                <div className="text-sm font-bold text-slate-200 truncate">{gameState.location.name}</div>
             </div>
         </div>
      )}

      {/* COMBAT WIDGET */}
      {gameState.activeEnemy && (
         <div className="p-4 bg-red-950/20 border-b border-red-900/50 animate-in slide-in-from-top duration-500 relative overflow-hidden group">
            {/* Pulsing overlay */}
            <div className="absolute inset-0 bg-red-500/5 animate-[pulse_2s_infinite]" />

            <div className="relative z-10">
               <div className="flex justify-between items-start mb-2">
                  <span className="text-xs font-bold text-red-500 uppercase tracking-widest animate-pulse flex items-center gap-1">
                     <Sword size={12} /> Combat Active
                  </span>
                  <span className="text-[10px] bg-red-900/40 text-red-300 px-2 py-0.5 rounded border border-red-800/50 uppercase">
                     {gameState.activeEnemy.type}
                  </span>
               </div>

               <div className="flex gap-3 items-center">
                  <div className="w-12 h-12 rounded-lg border-2 border-red-900/50 bg-slate-900 overflow-hidden shadow-lg relative">
                     {gameState.activeEnemy.imageUrl ? (
                        <img src={gameState.activeEnemy.imageUrl} alt="Enemy" className="w-full h-full object-cover" />
                     ) : (
                        <div className="w-full h-full flex items-center justify-center text-red-700"><Skull size={24} /></div>
                     )}
                  </div>
                  <div className="flex-1 space-y-1">
                     <div className="font-bold text-red-100">{gameState.activeEnemy.name}</div>
                     <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden border border-red-900/30">
                        <div 
                          className="h-full bg-red-600 transition-all duration-300"
                          style={{ width: `${(gameState.activeEnemy.currentHp / gameState.activeEnemy.maxHp) * 100}%` }}
                        />
                     </div>
                     <div className="text-[10px] text-red-400 text-right">
                        {gameState.activeEnemy.currentHp} / {gameState.activeEnemy.maxHp} HP
                     </div>
                  </div>
               </div>
            </div>
         </div>
      )}

      {/* Header / Portrait */}
      <div className="p-4 text-center border-b border-slate-800 bg-slate-950 relative">
        <h1 className="text-xl font-bold text-amber-500 tracking-wider fantasy-font mb-4">INFINITY QUEST</h1>

        {/* Character Portrait */}
        <div className="relative w-24 h-24 mx-auto mb-3 rounded-full border-2 border-slate-700 overflow-hidden shadow-lg group">
           {gameState.portraitUrl ? (
             <img src={gameState.portraitUrl} alt="Character" className="w-full h-full object-cover" />
           ) : (
             <div className="w-full h-full bg-slate-800 flex items-center justify-center">
               {getClassIcon()}
             </div>
           )}
           <div className="absolute inset-0 ring-inset ring-2 ring-black/20 rounded-full" />
        </div>

        {/* Companion Slot (If exists) */}
        {gameState.companion && (
          <div className="absolute top-16 right-4 w-12 h-12 rounded-full border-2 border-amber-500/50 bg-slate-800 shadow-xl overflow-hidden animate-in fade-in zoom-in" title={gameState.companion.name}>
             {gameState.companion.portraitUrl ? (
                <img src={gameState.companion.portraitUrl} alt="Companion" className="w-full h-full object-cover" />
             ) : (
                <div className="w-full h-full flex items-center justify-center text-amber-500"><Cat size={20} /></div>
             )}
          </div>
        )}

        <div className="flex items-center justify-center gap-2 mb-1">
           {getClassIcon()}
           <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">{gameState.title || 'Novice'} {gameState.playerClass}</p>
        </div>

        {/* Ascension Badge */}
        {gameState.ascensionLevel > 0 && (
           <div className="flex items-center justify-center gap-1 mb-3 text-[10px] text-purple-400 font-bold uppercase tracking-widest">
              <Sparkles size={10} /> Ascension {gameState.ascensionLevel}
           </div>
        )}

        {/* HP Bar & Gold */}
        <div className="max-w-[200px] mx-auto grid grid-cols-2 gap-2 mb-2">
           <div>
             <div className="flex justify-between text-[10px] text-red-400 font-bold uppercase mb-1">
                <span className="flex items-center gap-1"><Heart size={10} fill="currentColor" /> HP</span>
                <span>{gameState.currentHp}/{gameState.maxHp}</span>
             </div>
             <div className="h-1.5 w-full bg-slate-900 rounded-full overflow-hidden border border-slate-800">
                <div 
                  className="h-full bg-gradient-to-r from-red-800 to-red-500 transition-all duration-500 ease-out"
                  style={{ width: `${hpPercentage}%` }}
                />
             </div>
           </div>

           <div className="flex items-end justify-end">
              <div className="flex items-center gap-1.5 bg-slate-900/50 px-2 py-0.5 rounded-lg border border-yellow-500/20">
                 <Coins size={12} className="text-yellow-500" />
                 <span className="text-xs font-bold text-yellow-400">{gameState.gold || 0}</span>
              </div>
           </div>
        </div>

        {/* Survival Bars (Hunger & Thirst) */}
        <div className="max-w-[200px] mx-auto grid grid-cols-2 gap-2 mb-2">
           <div className="space-y-1">
              <div className={`h-1 w-full bg-slate-900 rounded-full overflow-hidden ${gameState.hunger < 25 ? 'animate-pulse ring-1 ring-orange-500/50' : ''}`} title="Hunger">
                 <div 
                   className="h-full bg-orange-500 transition-all duration-500"
                   style={{ width: `${gameState.hunger}%` }}
                 />
              </div>
              <div className="flex justify-between text-[9px] text-orange-400 font-bold uppercase">
                  <span className="flex items-center gap-1"><Utensils size={8} /> HUN</span>
              </div>
           </div>
           <div className="space-y-1">
              <div className={`h-1 w-full bg-slate-900 rounded-full overflow-hidden ${gameState.thirst < 25 ? 'animate-pulse ring-1 ring-blue-500/50' : ''}`} title="Thirst">
                 <div 
                   className="h-full bg-blue-500 transition-all duration-500"
                   style={{ width: `${gameState.thirst}%` }}
                 />
              </div>
              <div className="flex justify-between text-[9px] text-blue-400 font-bold uppercase">
                  <span className="flex items-center gap-1"><Droplets size={8} /> THR</span>
              </div>
           </div>
        </div>

        {/* ACT PROGRESS */}
        <div className="mt-2 pt-2 border-t border-slate-800/50">
           <div className="flex justify-between text-[10px] text-slate-500 font-bold uppercase mb-1">
              <span>{getActName(gameState.currentAct)}</span>
              <span>{Math.round(gameState.actProgress)}%</span>
           </div>
           <div className="h-1 w-full bg-slate-900 rounded-full overflow-hidden">
               <div 
                 className={`h-full transition-all duration-700 ${gameState.isBossFight ? 'bg-red-600 animate-pulse' : 'bg-slate-600'}`}
                 style={{ width: `${gameState.actProgress}%` }}
               />
           </div>
        </div>
      </div>

      {/* Tabs */}
      <div className="flex border-b border-slate-800 bg-slate-900/50 overflow-x-auto custom-scrollbar">
        <button onClick={() => setActiveTab('status')} className={`flex-1 min-w-[50px] py-3 transition-colors ${activeTab === 'status' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-slate-600 hover:text-slate-400'}`}><Trophy size={16} className="mx-auto" /></button>
        <button onClick={() => setActiveTab('inventory')} className={`flex-1 min-w-[50px] py-3 transition-colors ${activeTab === 'inventory' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-slate-600 hover:text-slate-400'}`}><Backpack size={16} className="mx-auto" /></button>
        <button onClick={() => setActiveTab('abilities')} className={`flex-1 min-w-[50px] py-3 transition-colors ${activeTab === 'abilities' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-slate-600 hover:text-slate-400'}`}><Zap size={16} className="mx-auto" /></button>
        <button onClick={() => setActiveTab('codex')} className={`flex-1 min-w-[50px] py-3 transition-colors ${activeTab === 'codex' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-slate-600 hover:text-slate-400'}`}><Book size={16} className="mx-auto" /></button>
        <button onClick={() => setActiveTab('social')} className={`flex-1 min-w-[50px] py-3 transition-colors ${activeTab === 'social' ? 'text-amber-500 border-b-2 border-amber-500' : 'text-slate-600 hover:text-slate-400'}`}><Flag size={16} className="mx-auto" /></button>
      </div>

      <div className="flex-1 overflow-y-auto p-4 space-y-6 custom-scrollbar">

        {/* STATUS TAB */}
        {activeTab === 'status' && (
          <div className="space-y-6 animate-fade-in">
             {/* XP Section */}
            <div className="space-y-3 bg-slate-800/40 p-4 rounded-xl border border-slate-700/50">
              <div className="flex items-center justify-between border-b border-slate-700 pb-2 mb-2">
                <h3 className="font-bold text-sm uppercase tracking-wider text-slate-300 flex items-center gap-2">
                  <Trophy size={14} className="text-yellow-500" />
                  Level {gameState.level}
                </h3>
              </div>
              <div className="space-y-1">
                <div className="flex justify-between text-[10px] text-slate-400 font-medium uppercase">
                  <span>XP</span>
                  <span>{gameState.currentXp} / {gameState.nextLevelXp}</span>
                </div>
                <div className="h-2 w-full bg-slate-900 rounded-full overflow-hidden border border-slate-700">
                  <div 
                    className="h-full bg-gradient-to-r from-amber-600 to-yellow-500 transition-all duration-1000 ease-out"
                    style={{ width: `${xpPercentage}%` }}
                  />
                </div>
              </div>
            </div>

            {/* Stats Grid */}
            <div className="grid grid-cols-2 gap-3">
              <div className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50 flex flex-col gap-1">
                <div className="flex items-center gap-2 text-red-400 mb-1">
                   <BicepsFlexed size={16} />
                   <span className="text-[10px] font-bold uppercase">STR</span>
                </div>
                <span className="text-2xl font-bold text-white">{gameState.stats.strength}</span>
              </div>
              <div className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50 flex flex-col gap-1">
                <div className="flex items-center gap-2 text-blue-400 mb-1">
                   <Brain size={16} />
                   <span className="text-[10px] font-bold uppercase">INT</span>
                </div>
                <span className="text-2xl font-bold text-white">{gameState.stats.intelligence}</span>
              </div>
              <div className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50 flex flex-col gap-1">
                <div className="flex items-center gap-2 text-green-400 mb-1">
                   <Activity size={16} />
                   <span className="text-[10px] font-bold uppercase">STA</span>
                </div>
                <span className="text-2xl font-bold text-white">{gameState.stats.stamina}</span>
              </div>
              <div className="bg-slate-800/40 p-3 rounded-xl border border-slate-700/50 flex flex-col gap-1">
                <div className="flex items-center gap-2 text-purple-400 mb-1">
                   <MessageCircle size={16} />
                   <span className="text-[10px] font-bold uppercase">CHA</span>
                </div>
                <span className="text-2xl font-bold text-white">{gameState.stats.charisma}</span>
              </div>
            </div>

             {/* Companion Details */}
             {gameState.companion && (
                <div className="bg-slate-800/40 p-4 rounded-xl border border-slate-700/50 space-y-2">
                   <div className="flex items-center gap-2 text-amber-400 border-b border-amber-900/30 pb-2">
                      <Cat size={16} />
                      <h3 className="font-bold text-sm uppercase tracking-wider">{gameState.companion.name}</h3>
                      <span className="text-xs text-slate-500 ml-auto">{gameState.companion.species}</span>
                   </div>
                   <p className="text-xs text-slate-400 italic">"{gameState.companion.personality}"</p>
                </div>
             )}

            {/* Quest Section */}
            <div className="space-y-3">
              <div className="flex items-center gap-2 text-blue-400 border-b border-blue-900/30 pb-2">
                <Scroll size={18} />
                <h3 className="font-bold text-sm uppercase tracking-wider">
                  {isGerman ? 'Aktuelle Quest' : 'Current Quest'}
                </h3>
              </div>
              <div className="bg-blue-900/10 border border-blue-900/30 rounded-lg p-4">
                 <p className="text-slate-300 italic text-sm leading-relaxed">
                   {gameState.currentQuest || (isGerman ? "Deine Reise beginnt erst..." : "Your journey is just beginning...")}
                 </p>
              </div>
            </div>
          </div>
        )}

        {/* INVENTORY TAB */}
        {activeTab === 'inventory' && (
          <div className="space-y-4 animate-fade-in">
             <div className="flex items-center justify-between border-b border-emerald-900/30 pb-2">
                <div className="flex items-center gap-2 text-emerald-400">
                  <Backpack size={18} />
                  <h3 className="font-bold text-sm uppercase tracking-wider">
                    {isGerman ? 'Tasche' : 'Backpack'}
                  </h3>
                  <span className="text-xs bg-slate-800 px-2 py-0.5 rounded-full text-slate-400">{gameState.inventory.length}</span>
                </div>

                {/* Crafting Toggle */}
                <button 
                  onClick={() => {
                    setIsCraftingMode(!isCraftingMode);
                    setSelectedCraftItems([]);
                  }}
                  className={`p-1.5 rounded-lg transition-all ${isCraftingMode ? 'bg-amber-600 text-white shadow-lg' : 'bg-slate-800 text-slate-400 hover:text-white'}`}
                  title={isGerman ? 'Handwerksmodus' : 'Crafting Mode'}
                >
                  <Hammer size={16} />
                </button>
              </div>

             {isCraftingMode && (
                <div className="bg-amber-900/20 border border-amber-500/30 rounded-lg p-3 text-xs text-amber-200 text-center mb-2 animate-in slide-in-from-top-2">
                   {selectedCraftItems.length === 2 ? (
                      <button 
                        onClick={handleFuse}
                        className="w-full py-2 bg-amber-600 hover:bg-amber-500 text-white font-bold rounded shadow-lg animate-pulse flex items-center justify-center gap-2"
                      >
                        <Sparkles size={14} /> Fuse Items
                      </button>
                   ) : (
                      <span>Select exactly 2 items to combine</span>
                   )}
                </div>
             )}

             {gameState.inventory.length === 0 ? (
                <div className="text-slate-600 text-sm text-center py-10 italic flex flex-col items-center gap-2">
                  <Backpack size={32} className="opacity-20" />
                  {isGerman ? 'Dein Inventar ist leer.' : 'Your inventory is empty.'}
                </div>
              ) : (
                <ul className="space-y-2">
                  {gameState.inventory.map((item, index) => {
                    const isSelected = selectedCraftItems.includes(item);
                    return (
                      <li 
                        key={index} 
                        onClick={() => toggleCraftItem(item)}
                        className={`border rounded-lg p-3 flex items-start gap-3 transition-all duration-300 ${getRarityClass(item.rarity)} ${isCraftingMode ? 'cursor-pointer hover:scale-105' : ''} ${isSelected ? 'ring-2 ring-amber-500 scale-105 bg-amber-500/20' : ''}`}
                      >
                        <div className="mt-1">
                          {item.type === 'Weapon' ? <Sword size={14} /> : <div className="w-3 h-3 rounded-full bg-current opacity-50" />}
                        </div>
                        <div className="flex flex-col">
                           <span className="text-sm font-bold opacity-90">{item.name}</span>
                           <span className="text-xs text-slate-500 font-bold uppercase tracking-wider">{item.rarity} {item.type}</span>
                        </div>
                        {isSelected && <div className="ml-auto text-amber-500"><Sparkles size={14} /></div>}
                      </li>
                    );
                  })}
                </ul>
              )}
          </div>
        )}

        {/* ABILITIES TAB */}
        {activeTab === 'abilities' && (
           <div className="space-y-4 animate-fade-in">
              <div className="flex items-center gap-2 text-purple-400 border-b border-purple-900/30 pb-2">
                <Zap size={18} />
                <h3 className="font-bold text-sm uppercase tracking-wider">
                  {isGerman ? 'Fähigkeiten' : 'Abilities'}
                </h3>
              </div>

              {gameState.abilities && gameState.abilities.length > 0 ? (
                 <ul className="space-y-3">
                    {gameState.abilities.map((ability, idx) => (
                       <li key={idx} className="bg-slate-800/80 border border-slate-700 rounded-lg p-3 relative overflow-hidden group">
                          <div className="absolute top-0 right-0 p-2 opacity-10 group-hover:opacity-20 transition-opacity">
                             <Zap size={48} />
                          </div>
                          <h4 className="font-bold text-amber-500 mb-1">{ability.name}</h4>
                          <p className="text-xs text-slate-400 leading-relaxed">{ability.description}</p>
                       </li>
                    ))}
                 </ul>
              ) : (
                 <div className="text-slate-600 text-sm text-center py-10 italic flex flex-col items-center gap-2">
                    <Brain size={32} className="opacity-20" />
                    {isGerman ? 'Noch keine Fähigkeiten gelernt.' : 'No abilities learned yet.'}
                    <p className="text-xs text-slate-500 max-w-[150px]">Level up to unlock new perks.</p>
                 </div>
              )}
           </div>
        )}

        {/* CODEX TAB */}
        {activeTab === 'codex' && (
           <div className="space-y-4 animate-fade-in">
              <div className="flex gap-2 mb-4">
                 <button 
                   onClick={() => setCodexFilter('Bestiary')}
                   className={`flex-1 py-2 text-xs uppercase font-bold border rounded-lg transition-colors ${codexFilter === 'Bestiary' ? 'bg-red-900/20 border-red-500 text-red-400' : 'border-slate-700 text-slate-500'}`}
                 >
                   <Skull size={14} className="mx-auto mb-1" />
                   Bestiary
                 </button>
                 <button 
                   onClick={() => setCodexFilter('Atlas')}
                   className={`flex-1 py-2 text-xs uppercase font-bold border rounded-lg transition-colors ${codexFilter === 'Atlas' ? 'bg-cyan-900/20 border-cyan-500 text-cyan-400' : 'border-slate-700 text-slate-500'}`}
                 >
                   <Map size={14} className="mx-auto mb-1" />
                   Atlas
                 </button>
              </div>

              {/* Dynamic Map Display in Atlas */}
              {codexFilter === 'Atlas' && gameState.location?.name && (
                <div className="mb-6 animate-fade-in">
                   <div className="bg-slate-800 rounded-xl overflow-hidden border border-slate-700 shadow-xl relative group">
                      <div className="absolute top-2 left-2 z-10 bg-black/60 backdrop-blur px-2 py-1 rounded text-xs font-bold text-cyan-300 border border-cyan-500/30">
                         Current Location
                      </div>

                      {gameState.maps[gameState.location.name] ? (
                         <img 
                           src={gameState.maps[gameState.location.name]} 
                           alt="Current Map" 
                           className="w-full aspect-square object-cover sepia-[.5] brightness-90 hover:brightness-100 hover:sepia-0 transition-all duration-700"
                         />
                      ) : (
                         <div className="w-full aspect-square bg-slate-900 flex flex-col items-center justify-center text-slate-500 gap-3">
                            <Loader className="animate-spin text-cyan-500" />
                            <span className="text-xs">Charting Region...</span>
                         </div>
                      )}

                      <div className="p-3 bg-slate-900/90 border-t border-slate-700">
                         <h4 className="font-bold text-cyan-100">{gameState.location.name}</h4>
                         <p className="text-xs text-slate-400">{gameState.location.biome}</p>
                      </div>
                   </div>
                </div>
              )}

              {gameState.codex && gameState.codex.filter(c => c.category === codexFilter).length > 0 ? (
                 <ul className="space-y-3">
                    {gameState.codex.filter(c => c.category === codexFilter).map((entry, idx) => (
                       <li key={idx} className="bg-slate-900 border border-slate-700 rounded-lg p-3">
                          <h4 className={`font-bold text-sm mb-1 ${codexFilter === 'Bestiary' ? 'text-red-400' : 'text-cyan-400'}`}>{entry.name}</h4>
                          <p className="text-xs text-slate-400 leading-relaxed italic">"{entry.description}"</p>
                       </li>
                    ))}
                 </ul>
              ) : (
                 <div className="text-slate-600 text-sm text-center py-10 italic">
                    {isGerman ? 'Noch keine Einträge entdeckt.' : 'No discoveries yet.'}
                 </div>
              )}
           </div>
        )}

        {/* SOCIAL TAB (FACTIONS & ACHIEVEMENTS) */}
        {activeTab === 'social' && (
          <div className="space-y-6 animate-fade-in">

             {/* Reputation Section */}
             <div className="space-y-3">
               <div className="flex items-center gap-2 text-orange-400 border-b border-orange-900/30 pb-2">
                 <Flag size={18} />
                 <h3 className="font-bold text-sm uppercase tracking-wider">
                   {isGerman ? 'Ruf' : 'Reputation'}
                 </h3>
               </div>

               <div className="space-y-4">
                 {gameState.reputation.map((rep, idx) => {
                   const width = Math.min(100, Math.max(0, (rep.value + 100) / 2)); // -100 to 100 -> 0 to 100
                   return (
                     <div key={idx} className="space-y-1">
                        <div className="flex justify-between text-xs">
                           <span className="font-bold text-slate-300">{rep.faction}</span>
                           <span className="text-slate-500">{rep.status} ({rep.value})</span>
                        </div>
                        <div className="h-1.5 w-full bg-slate-800 rounded-full overflow-hidden">
                           <div className={`h-full transition-all duration-700 ${getReputationColor(rep.status)}`} style={{ width: `${width}%` }} />
                        </div>
                     </div>
                   );
                 })}
               </div>
             </div>

             {/* Achievements Section */}
             <div className="space-y-3 pt-4 border-t border-slate-800">
               <div className="flex items-center gap-2 text-yellow-400 border-b border-yellow-900/30 pb-2">
                 <Medal size={18} />
                 <h3 className="font-bold text-sm uppercase tracking-wider">
                   {isGerman ? 'Erfolge' : 'Achievements'}
                 </h3>
                 <span className="ml-auto text-xs bg-slate-800 px-2 py-0.5 rounded-full">{gameState.unlockedAchievements?.length || 0}</span>
               </div>

               <div className="grid grid-cols-4 gap-2">
                  {ACHIEVEMENTS_LIST.map((ach) => {
                    const isUnlocked = gameState.unlockedAchievements?.includes(ach.id);
                    return (
                       <div key={ach.id} className={`aspect-square rounded-lg border flex items-center justify-center relative group ${isUnlocked ? 'bg-slate-800 border-yellow-500/50 text-yellow-500' : 'bg-slate-900 border-slate-800 text-slate-700'}`}>
                          <Medal size={20} className={!isUnlocked ? 'opacity-20' : ''} />

                          {/* Tooltip */}
                          <div className="absolute bottom-full left-1/2 -translate-x-1/2 mb-2 w-40 bg-black/90 border border-slate-700 p-2 rounded text-[10px] pointer-events-none opacity-0 group-hover:opacity-100 transition-opacity z-50 text-center">
                             <div className={`font-bold mb-1 ${isUnlocked ? 'text-yellow-400' : 'text-slate-500'}`}>{ach.title}</div>
                             <div className="text-slate-400">{ach.description}</div>
                          </div>
                       </div>
                    );
                  })}
               </div>
             </div>

          </div>
        )}

      </div>

      <div className="mt-auto p-4 border-t border-slate-800 text-xs text-slate-600 text-center bg-slate-900/80">
        <div className="flex items-center justify-center gap-2">
           <ShieldAlert size={12} />
           <span>Auto-Save Active</span>
        </div>
      </div>
    </div>
  );
};

export default Sidebar;
